function htmlEscape(value: unknown) {
  return String(value ?? "").replace(/[&<>"']/g, (ch) => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", "\"": "&quot;", "'": "&#39;" }[ch] || ch));
}

function safeInlineJson(value: unknown) {
  return JSON.stringify(value)
    .replace(/</g, "\\u003c")
    .replace(/>/g, "\\u003e")
    .replace(/&/g, "\\u0026")
    .replace(/\u2028/g, "\\u2028")
    .replace(/\u2029/g, "\\u2029");
}

function normalizeFnDocumentCompany(value?: Partial<FnCompanyInfo> | null): FnCompanyInfo {
  const next = { ...FN_DEFAULT_DOCUMENT_COMPANY, ...(value || {}) };
  return {
    ...next,
    business_no: String(next.business_no || FN_DEFAULT_DOCUMENT_COMPANY.business_no),
    representative_name: String(next.representative_name || FN_DEFAULT_DOCUMENT_COMPANY.representative_name),
    phone: String(next.phone || FN_DEFAULT_DOCUMENT_COMPANY.phone),
    fax: String(next.fax || FN_DEFAULT_DOCUMENT_COMPANY.fax),
    address: composeFnSettingsAddress(next) || FN_DEFAULT_DOCUMENT_COMPANY.address,
    seal_image_url: String(next.seal_image_url || FN_SEAL_FALLBACK_URL),
  };
}

function getFnDocumentCompanyInfo() {
  if (typeof window === "undefined") return normalizeFnDocumentCompany();
  try {
    return normalizeFnDocumentCompany(JSON.parse(window.localStorage.getItem(FN_SETTINGS_COMPANY_STORAGE_KEY) || "null") as Partial<FnCompanyInfo> | null);
  } catch {
    return normalizeFnDocumentCompany();
  }
}

function amountToKoreanText(value: number) {
  const units = ["", "만", "억", "조"];
  const digits = ["", "일", "이", "삼", "사", "오", "육", "칠", "팔", "구"];
  const smallUnits = ["", "십", "백", "천"];
  const clean = Math.max(0, Math.round(Number(value) || 0));
  if (!clean) return "영";
  const groups = String(clean).replace(/\B(?=(\d{4})+(?!\d))/g, ",").split(",").map(Number);
  return groups.map((group, groupIndex) => {
    if (!group) return "";
    const chars = String(group).padStart(4, "0").split("").map(Number);
    const part = chars.map((num, index) => {
      if (!num) return "";
      const unitIndex = 3 - index;
      return `${digits[num]}${smallUnits[unitIndex]}`;
    }).join("");
    const unit = units[groups.length - groupIndex - 1] || "";
    return `${part}${unit}`;
  }).filter(Boolean).join("");
}

type ProductSearchAttributeFilter = "plain" | "set" | "rg" | "import" | "all";
const productSearchAttributeOptions: Array<{ value: ProductSearchAttributeFilter; label: string }> = [
  { value: "plain", label: "일반" },
  { value: "set", label: "SET" },
  { value: "rg", label: "RG" },
  { value: "import", label: "수입연동" },
  { value: "all", label: "전체" },
];

function entryDateFromDate(date: Date) {
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, "0");
  const day = String(date.getDate()).padStart(2, "0");
  return `${year}-${month}-${day}`;
}

function entryDateToday() {
  return entryDateFromDate(new Date());
}

function entryDateDaysAgo(days: number) {
  const date = new Date();
  date.setDate(date.getDate() - days);
  return entryDateFromDate(date);
}

function normalizeEntryDate(value: unknown) {
  const text = String(value || "").trim();
  if (!text) return "";
  if (/^\d{8}$/.test(text)) return `${text.slice(0, 4)}-${text.slice(4, 6)}-${text.slice(6, 8)}`;
  return text.slice(0, 10);
}

function entryDateFilterKey(value: unknown) {
  return normalizeEntryDate(value).replace(/\D/g, "").slice(0, 8);
}

function entryRowDate(row: Record<string, unknown>) {
  return normalizeEntryDate(row.io_date || row.sale_date || row.purchase_date || row.created_at);
}

function entryRowCustomer(row: Record<string, unknown>, mode: SalesPurchaseMode) {
  return String(row.cust_name || row.customer_name || row.supplier_name || row.cust_code || (mode === "sales" ? "거래처" : "구매처") || "-");
}

function entryRowProduct(row: Record<string, unknown>) {
  return String(row.representative_product_name || row.prod_name || row.product_name || row.representative_product_code || row.prod_cd || row.sku || "-");
}

function entryRowProductCode(row: Record<string, unknown>) {
  return String(row.representative_product_code || row.prod_cd || row.product_code || row.sku || "");
}

function entryRowWarehouse(row: Record<string, unknown>) {
  return String(row.wh_cd || row.warehouse_code || row.warehouse_name || "100");
}

function entryRowAmount(row: Record<string, unknown>) {
  return Number(row.total_amount || row.supply_amount || row.supply_amt || 0);
}

function entryRowQty(row: Record<string, unknown>) {
  return Number(row.qty || row.quantity || row.order_qty || 0);
}

function entryRowMemo(row: Record<string, unknown>) {
  return String(row.remarks || row.memo || "-");
}

function entryRowKey(row: Record<string, unknown>, mode: SalesPurchaseMode, index = 0) {
  const sourceRef = String(row.source_ref_id || "");
  const manualMatch = sourceRef.match(/^(manual-(?:sale|purchase)-\d+)/);
  const sourceBase = sourceRef.replace(/-\d+-.+$/, "");
  const groupedSourceRef = sourceBase && sourceBase !== sourceRef ? sourceBase : "";
  const batchId = String(row.upload_batch_id || "");
  return String(row.entry_group_key || (batchId ? `batch:${batchId}` : "") || (manualMatch?.[1] ? `manual:${manualMatch[1]}` : "") || (groupedSourceRef ? `source:${groupedSourceRef}` : "") || row.id || `${mode}-${index}`);
}

function entryRowSourceRefBase(row: Record<string, unknown>, mode: SalesPurchaseMode) {
  const sourceRef = String(row.source_ref_id || "");
  const manualMatch = sourceRef.match(/^(manual-(?:sale|purchase)-\d+)/);
  if (manualMatch?.[1]) return manualMatch[1];
  const sourceBase = sourceRef.replace(/-\d+-.+$/, "");
  if (sourceBase && sourceBase !== sourceRef) return sourceBase;
  return `${mode === "sales" ? "manual-sale" : "manual-purchase"}-${Date.now()}`;
}

function compactEntryNumber(date: string, sequence: number) {
  const key = entryDateFilterKey(date);
  const yymmdd = key.length === 8 ? key.slice(2) : entryDateToday().replace(/\D/g, "").slice(2);
  return `${yymmdd}-${sequence}`;
}

function summarizeEntryDisplayRows(rows: Array<Record<string, unknown>>, mode: SalesPurchaseMode) {
  const groups = new Map<string, { rows: Array<Record<string, unknown>>; firstSeen: number }>();
  rows.forEach((row, index) => {
    const key = entryRowKey(row, mode, index);
    const group = groups.get(key) || { rows: [], firstSeen: index };
    group.rows.push(row);
    groups.set(key, group);
  });
  return Array.from(groups.entries()).map(([key, group]) => {
    const sorted = [...group.rows].sort((left, right) => Number(left.upload_ser_no || 999999) - Number(right.upload_ser_no || 999999));
    const first = sorted[0] || {};
    return {
      ...first,
      id: key,
      entry_group_key: key,
      line_count: sorted.length === 1 ? Number(first.line_count || 1) : sorted.length,
      qty: sorted.reduce((total, row) => total + entryRowQty(row), 0),
      supply_amt: sorted.reduce((total, row) => total + entryRowAmount(row), 0),
      supply_amount: sorted.reduce((total, row) => total + entryRowAmount(row), 0),
      total_amount: sorted.reduce((total, row) => total + entryRowAmount(row), 0),
      representative_product_code: entryRowProductCode(first),
      representative_product_name: entryRowProduct(first),
      _recent_order: group.firstSeen,
    };
  }).sort((left, right) => Number(left._recent_order) - Number(right._recent_order))
    .map(({ _recent_order: _removed, ...row }) => row);
}

function filterEntryRows(rows: Array<Record<string, unknown>>, mode: SalesPurchaseMode, filters: Record<string, string>, lineRows: Array<Record<string, unknown>> = []) {
  const from = entryDateFilterKey(filters.from);
  const to = entryDateFilterKey(filters.to);
  const customerNeedles = parseHistoryCustomerFilter(filters.customer);
  const warehouseNeedle = filters.warehouse.trim().toLowerCase();
  const productNeedle = filters.product.trim().toLowerCase();
  const lineProductMatches = new Set<string>();
  if (productNeedle) {
    lineRows.forEach((line, index) => {
      const haystack = `${entryRowProductCode(line)} ${entryRowProduct(line)}`.toLowerCase();
      if (haystack.includes(productNeedle)) lineProductMatches.add(entryRowKey(line, mode, index));
    });
  }
  return summarizeEntryDisplayRows(rows, mode).filter((row) => {
    const date = entryDateFilterKey(entryRowDate(row));
    if (from && date && date < from) return false;
    if (to && date && date > to) return false;
    if (customerNeedles.length) {
      const sourceRow = row as Record<string, unknown>;
      const customerHaystack = [entryRowCustomer(row, mode), sourceRow.cust_code, sourceRow.customer_code, sourceRow.supplier_code, sourceRow.cust_name, sourceRow.customer_name, sourceRow.supplier_name]
        .map((value) => String(value || "").toLowerCase())
        .join(" ");
      if (!customerNeedles.some((needle) => customerHaystack.includes(needle))) return false;
    }
    if (warehouseNeedle && !entryRowWarehouse(row).toLowerCase().includes(warehouseNeedle)) return false;
    if (productNeedle) {
      const representativeHaystack = `${entryRowProductCode(row)} ${entryRowProduct(row)}`.toLowerCase();
      if (!representativeHaystack.includes(productNeedle) && !lineProductMatches.has(entryRowKey(row, mode))) return false;
    }
    return true;
  });
}

const historyCustomerFilterSeparator = "\u001f";

function parseHistoryCustomerFilter(value: string) {
  return value
    .split(historyCustomerFilterSeparator)
    .map((item) => item.trim().toLowerCase())
    .filter(Boolean);
}

function customerSearchKey(customer: FnCustomer, index = 0) {
  return String(customer.id || customer.customer_code || customer.cust_code || customer.customer_name || customer.cust_name || index);
}

function customerSearchLabel(customer: FnCustomer) {
  return String(customer.customer_name || customer.cust_name || customer.customer_code || customer.cust_code || "-");
}

function customerSearchSubLabel(customer: FnCustomer) {
  const code = String(customer.customer_code || customer.cust_code || "");
  const type = customerAttributeLabel(customer.customer_type || customer.customer_type_label);
  return [code, type].filter(Boolean).join(" / ");
}

function customerHistoryFilterValue(customers: FnCustomer[]) {
  return customers.flatMap((customer) => [
    String(customer.customer_code || customer.cust_code || "").trim(),
    String(customer.customer_name || customer.cust_name || "").trim(),
  ]).filter(Boolean).join(historyCustomerFilterSeparator);
}

function customerHistoryDraftLabel(customers: FnCustomer[]) {
  return customers.map(customerSearchLabel).filter(Boolean).join(", ");
}

function SalesHistoryCustomerPicker({
  query,
  mode,
  onClose,
  onApply,
}: {
  query: string;
  mode: SalesPurchaseMode;
  onClose: () => void;
  onApply: (customers: FnCustomer[]) => void;
}) {
  const [customers, setCustomers] = useState<FnCustomer[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedKeys, setSelectedKeys] = useState<string[]>([]);
  const [activeIndex, setActiveIndex] = useState<number | null>(null);
  const keyboardRootRef = useRef<HTMLDivElement | null>(null);
  const focusedOnceRef = useRef(false);
  const normalizedQuery = query.trim().toLowerCase();
  const visibleCustomers = customers.filter((customer) => {
    if (!normalizedQuery) return true;
    return [customer.customer_code, customer.cust_code, customer.customer_name, customer.cust_name, customer.contact_name, customer.phone, customer.memo]
      .some((value) => String(value || "").toLowerCase().includes(normalizedQuery));
  });
  const visibleKeys = visibleCustomers.map(customerSearchKey);
  const selection = useCheckboxColumnSelection({ keys: visibleKeys, selectedKeys, setSelectedKeys });

  useEffect(() => {
    if (activeIndex !== null && activeIndex >= visibleCustomers.length) {
      setActiveIndex(visibleCustomers.length ? visibleCustomers.length - 1 : null);
    }
  }, [activeIndex, visibleCustomers.length]);

  useEffect(() => {
    if (focusedOnceRef.current || loading) return;
    focusedOnceRef.current = true;
    window.setTimeout(() => keyboardRootRef.current?.focus(), 0);
  }, [loading]);

  useEffect(() => {
    let alive = true;
    setLoading(true);
    cachedClientJson<{ customers?: FnCustomer[] }>("/api/fnos/customers?page=1&pageSize=5000", { ttl: 60_000, storageTtl: 5 * 60_000 })
      .then((data) => {
        if (!alive) return;
        setCustomers(sortRowsByManagementName(data.customers || [], (customer) => customer.customer_name || customer.cust_name, (customer) => customer.customer_code || customer.cust_code));
      })
      .catch(() => {
        if (alive) setCustomers([]);
      })
      .finally(() => {
        if (alive) setLoading(false);
      });
    return () => {
      alive = false;
    };
  }, []);

  function applySelection() {
    const selectedSet = new Set(selectedKeys);
    const picked = visibleCustomers.filter((customer, index) => selectedSet.has(customerSearchKey(customer, index)));
    if (!picked.length) {
      window.alert("검색할 거래처를 선택해 주세요.");
      return;
    }
    onApply(picked);
  }

  function applyKeyboardSelection() {
    const targetIndex = activeIndex ?? 0;
    const picked = visibleCustomers[targetIndex];
    if (!picked) {
      window.alert("검색할 거래처를 선택해 주세요.");
      return;
    }
    onApply([picked]);
  }

  function handleKeyboardPick(event: KeyboardEvent<HTMLDivElement>) {
    if (event.key === "ArrowDown") {
      event.preventDefault();
      setActiveIndex((index) => index === null ? 0 : Math.min(visibleCustomers.length - 1, index + 1));
      return;
    }
    if (event.key === "ArrowUp") {
      event.preventDefault();
      setActiveIndex((index) => index === null ? Math.max(0, visibleCustomers.length - 1) : Math.max(0, index - 1));
      return;
    }
    if (event.key === "Enter") {
      event.preventDefault();
      applyKeyboardSelection();
    }
  }

  return (
    <FormModal
      title={mode === "sales" ? "거래처 검색" : "구매처 검색"}
      description={`${query || "전체"} 검색 결과에서 거래처를 선택합니다.`}
      onClose={onClose}
      size="lg"
      footer={
        <>
          <ActionButton type="button" variant="secondary" onClick={onClose}>닫기</ActionButton>
          <ActionButton type="button" onClick={applySelection}>검색</ActionButton>
        </>
      }
    >
      <div ref={keyboardRootRef} tabIndex={0} onKeyDown={handleKeyboardPick} className="outline-none">
        <div className="mb-3 text-xs font-bold text-slate-500">
          검색값 {query || "-"} / 선택 {selectedKeys.length.toLocaleString("ko-KR")}개 / 결과 {visibleCustomers.length.toLocaleString("ko-KR")}건
        </div>
        <div className="max-h-[52vh] overflow-auto rounded-lg border border-slate-200 bg-white">
          <table className="w-full min-w-[720px] table-fixed text-sm">
            <thead className="bg-slate-50 text-xs font-black text-slate-500">
              <tr>
                <th className="w-16 px-2 py-2 text-center">
                  <input type="checkbox" className="h-4 w-4 rounded border-slate-300" checked={selection.allSelected} onChange={(event) => selection.toggleAll(event.target.checked)} />
                </th>
                <th className="w-36 px-2 py-2 text-left">거래처코드</th>
                <th className="px-2 py-2 text-left">거래처명</th>
                <th className="w-28 px-2 py-2 text-left">속성</th>
                <th className="w-32 px-2 py-2 text-left">담당자</th>
                <th className="w-36 px-2 py-2 text-left">전화번호</th>
              </tr>
            </thead>
            <tbody>
              {visibleCustomers.map((customer, index) => {
                const key = customerSearchKey(customer, index);
                const selected = selectedKeys.includes(key);
                const active = activeIndex === index;
                return (
                  <tr key={key} className={`border-t border-slate-100 ${active ? "bg-orange-100 ring-1 ring-inset ring-orange-300" : selected ? "bg-orange-50" : "hover:bg-orange-50/50"}`}>
                    <td className="px-2 py-2 text-center">
                      <SelectionNumberButton index={index} selected={selected} onMouseDown={(event) => selection.beginSelection(key, index, event)} onMouseEnter={() => selection.continueSelection(key, index)} />
                    </td>
                    <td className="truncate px-2 py-2 font-bold text-slate-600">{customer.customer_code || customer.cust_code || "-"}</td>
                    <td className="truncate px-2 py-2 font-black text-slate-900">{customerSearchLabel(customer)}</td>
                    <td className="truncate px-2 py-2 text-slate-500">{customerAttributeLabel(customer.customer_type || customer.customer_type_label)}</td>
                    <td className="truncate px-2 py-2 text-slate-500">{customer.contact_name || "-"}</td>
                    <td className="truncate px-2 py-2 text-slate-500">{customer.phone || "-"}</td>
                  </tr>
                );
              })}
              {!visibleCustomers.length && (
                <tr>
                  <td colSpan={6} className="px-3 py-8 text-center text-sm font-bold text-slate-400">{loading ? "" : "검색 결과가 없습니다."}</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </FormModal>
  );
}

