function composePersonnelAddress(employee: Partial<PersonnelEmployee>) {
  const road = String(employee.road_address || "").trim();
  const jibun = String(employee.jibun_address || "").trim();
  const detail = String(employee.detail_address || "").trim();
  const base = road || jibun || String(employee.address || "").trim();
  return [base, detail].filter(Boolean).join(" ");
}

function composeCustomerAddress(customer: Record<string, string>) {
  const road = String(customer.road_address || "").trim();
  const jibun = String(customer.jibun_address || "").trim();
  const detail = String(customer.detail_address || "").trim();
  const base = road || jibun || String(customer.address || "").trim();
  return [base, detail].filter(Boolean).join(" ");
}

function composeFnSettingsAddress(value: Partial<Pick<FnCompanyInfo & FnLocationInfo, "road_address" | "jibun_address" | "detail_address" | "address">>) {
  const road = String(value.road_address || "").trim();
  const jibun = String(value.jibun_address || "").trim();
  const detail = String(value.detail_address || "").trim();
  const base = road || jibun || String(value.address || "").trim();
  return [base, detail].filter(Boolean).join(" ");
}

function formatKoreanDateText(value?: string) {
  const digits = onlyDigits(value).slice(0, 8);
  if (digits.length === 8) return `${Number(digits.slice(0, 4))}년 ${Number(digits.slice(4, 6))}월 ${Number(digits.slice(6, 8))}일`;
  const date = String(value || "").trim();
  const match = date.match(/^(\d{4})-(\d{2})-(\d{2})$/);
  if (!match) return date || "-";
  return `${Number(match[1])}년 ${Number(match[2])}월 ${Number(match[3])}일`;
}

function formatDateDigitsInput(value?: string) {
  const digits = onlyDigits(value).slice(0, 8);
  if (digits.length <= 4) return digits;
  if (digits.length <= 6) return `${digits.slice(0, 4)}-${digits.slice(4)}`;
  return `${digits.slice(0, 4)}-${digits.slice(4, 6)}-${digits.slice(6)}`;
}

function imageFileToDataUrlForSettings(file: File) {
  return new Promise<string>((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(String(reader.result || ""));
    reader.onerror = () => reject(new Error("이미지를 읽지 못했습니다."));
    reader.readAsDataURL(file);
  });
}

function daumRoadAddressWithExtra(data: DaumPostcodeData) {
  const road = String(data.roadAddress || data.autoRoadAddress || "").trim();
  const buildingName = String(data.buildingName || "").trim();
  const bname = /[동로가]$/u.test(String(data.bname || "")) ? String(data.bname || "").trim() : "";
  const extras = [buildingName || bname].filter(Boolean);
  if (!road || !extras.length) return road;
  const extraText = extras.join(", ");
  return road.includes(extraText) ? road : `${road} (${extraText})`;
}

let daumPostcodeScriptPromise: Promise<void> | null = null;

function loadDaumPostcodeScript() {
  if (typeof window === "undefined") return Promise.reject(new Error("브라우저에서만 주소검색을 사용할 수 있습니다."));
  if (window.daum?.Postcode) return Promise.resolve();
  if (!daumPostcodeScriptPromise) {
    daumPostcodeScriptPromise = new Promise<void>((resolve, reject) => {
      const existing = document.querySelector<HTMLScriptElement>('script[data-fnos-daum-postcode="true"]');
      if (existing) {
        existing.addEventListener("load", () => resolve(), { once: true });
        existing.addEventListener("error", () => reject(new Error("Daum 우편번호 서비스를 불러오지 못했습니다.")), { once: true });
        return;
      }
      const script = document.createElement("script");
      script.src = "https://t1.daumcdn.net/mapjsapi/bundle/postcode/prod/postcode.v2.js";
      script.async = true;
      script.dataset.fnosDaumPostcode = "true";
      script.onload = () => resolve();
      script.onerror = () => reject(new Error("Daum 우편번호 서비스를 불러오지 못했습니다."));
      document.head.appendChild(script);
    });
  }
  return daumPostcodeScriptPromise.then(() => new Promise<void>((resolve) => {
    if (window.daum?.postcode?.load) window.daum.postcode.load(resolve);
    else resolve();
  }));
}

function DaumPostcodeModal({ onClose, onSelect }: { onClose: () => void; onSelect: (data: DaumPostcodeData) => void }) {
  const containerRef = useRef<HTMLDivElement | null>(null);

  useEscapeToClose(true, onClose);

  useEffect(() => {
    let alive = true;
    loadDaumPostcodeScript()
      .then(() => {
        if (!alive || !containerRef.current || !window.daum?.Postcode) return;
        containerRef.current.innerHTML = "";
        new window.daum.Postcode({
          width: "100%",
          height: "100%",
          oncomplete: (data) => {
            onSelect(data);
            onClose();
          },
        }).embed(containerRef.current);
      })
      .catch((err) => {
        if (!alive) return;
        window.alert(err instanceof Error ? err.message : "주소검색을 불러오지 못했습니다.");
        onClose();
      });
    return () => {
      alive = false;
    };
  }, [onClose, onSelect]);

  return (
    <SelectionModal title="주소검색" description="Daum/Kakao 우편번호 서비스에서 주소를 검색하고 선택해 주세요." onClose={onClose} size="md" className="overflow-hidden">
      <div ref={containerRef} className="h-[440px] w-full overflow-hidden rounded-md border border-slate-200 bg-white" />
    </SelectionModal>
  );
}

