function masterTemplate(tab: MasterTabKey) {
  return masterTabs.find((item) => item.key === tab) || masterTabs[0];
}

function isMasterTabKey(value: unknown): value is MasterTabKey {
  return typeof value === "string" && masterTabs.some((tab) => tab.key === value);
}

async function readXlsxObjects(file: File) {
  const buffer = await file.arrayBuffer();
  const xlsx = await loadXlsxModule();
  const workbook = xlsx.read(buffer, { type: "array", cellDates: false });
  const sheetName = workbook.SheetNames[0];
  const worksheet = workbook.Sheets[sheetName];
  return xlsx.utils.sheet_to_json<Record<string, unknown>>(worksheet, { defval: "", raw: false });
}

function MasterManagementPanel({
  summary,
  message,
  setMessage,
  sync,
  loadSummary,
}: {
  summary: SalesInventorySummary | null;
  message: string;
  setMessage: (value: string) => void;
  sync: (target: "products" | "inventory") => void;
  loadSummary: () => void;
}) {
  const searchParams = useSearchParams();
  const requestedMasterTab = searchParams.get("masterTab");
  const initialMasterTab = isMasterTabKey(requestedMasterTab) ? requestedMasterTab : "customers";
  const [activeMasterTab, setActiveMasterTab] = useState<MasterTabKey>(initialMasterTab);
  const activeConfig = masterTemplate(activeMasterTab);

  function rememberMasterTab(tab: MasterTabKey) {
    if (typeof window === "undefined") return;
    const params = new URLSearchParams(window.location.search);
    params.set("menu", "sales");
    params.set("salesSection", "master");
    params.set("masterTab", tab);
    window.history.replaceState(window.history.state, "", `/?${params.toString()}`);
  }

  useEffect(() => {
    if (isMasterTabKey(requestedMasterTab) && requestedMasterTab !== activeMasterTab) setActiveMasterTab(requestedMasterTab);
  }, [requestedMasterTab, activeMasterTab]);

  function openMasterTab(tab: MasterTabKey) {
    setActiveMasterTab(tab);
    rememberMasterTab(tab);
  }

  return (
    <div className="space-y-4">
      <div className="overflow-x-auto rounded-md border border-slate-200 bg-white p-2">
        <div className="flex min-w-max gap-1">
          {masterTabs.filter((tab) => tab.key !== "channels").map((tab) => (
            <button
              key={tab.key}
              type="button"
              onClick={() => openMasterTab(tab.key)}
              className={`h-10 rounded-md px-4 text-sm font-black ${
                activeMasterTab === tab.key ? "bg-orange-500 text-white shadow-sm hover:bg-orange-600" : "text-slate-500 hover:bg-orange-50 hover:text-orange-600"
              }`}
            >
              {tab.label}
            </button>
          ))}
        </div>
      </div>

      {activeMasterTab !== "products" && activeMasterTab !== "customers" && activeMasterTab !== "warehouses" && activeMasterTab !== "channelMappings" && (
        <MasterEntryPanel
          config={activeConfig}
          setMessage={setMessage}
          loadSummary={loadSummary}
        />
      )}

      {activeMasterTab === "customers" && (
        <CustomerManagementPanel message={message} setMessage={setMessage} />
      )}

      {activeMasterTab === "products" && (
        <ProductManagementPanel message={message} setMessage={setMessage} />
      )}

      {activeMasterTab === "warehouses" && <WarehouseManagementPanel message={message} setMessage={setMessage} />}

      {activeMasterTab === "channelMappings" && <ChannelProductMappingPanel />}

      {activeMasterTab === "channels" && (
        <Panel
          title="쇼핑몰 목록"
          subtitle="주문수집 대상 쇼핑몰과 API/엑셀 수집 방식을 관리합니다."
          action={<button type="button" className="rounded-md bg-orange-500 px-4 py-2 text-sm font-black text-white" onClick={async () => {
            const res = await fetch("/api/fnos/sales-channels", { method: "POST", headers: { "Content-Type": "application/json" }, credentials: "include", body: JSON.stringify({ seed: true }) });
            const data = await res.json().catch(() => ({}));
            setMessage(data.ok ? `기본 채널 ${data.count || 0}개를 저장했습니다.` : data.error || "채널 저장 실패");
            loadSummary();
          }}>기본 채널 생성</button>}
        >
          <ChannelTable rows={summary?.sales_channels || []} />
        </Panel>
      )}

    </div>
  );
}

function PersonnelAuthModal({
  onClose,
  onUnlock,
  onChangePassword,
}: {
  onClose: () => void;
  onUnlock: (password: string) => boolean;
  onChangePassword: (currentPassword: string, newPassword: string, confirmPassword: string) => boolean;
}) {
  const [password, setPassword] = useState("");
  const [currentPassword, setCurrentPassword] = useState("");
  const [newPassword, setNewPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");

  return (
    <FormModal
      title="인사관리 권한 확인"
      description="인사정보 보호를 위해 비밀번호를 한 번 더 입력해 주세요."
      onClose={onClose}
      size="sm"
      footer={
        <>
          <ActionButton type="button" variant="secondary" onClick={onClose}>닫기</ActionButton>
          <ActionButton type="button" onClick={() => onUnlock(password)}>확인</ActionButton>
        </>
      }
    >
      <div className="space-y-5">
        <FormField label="비밀번호" required>
          <input
            className={modalInputClass}
            type="password"
            value={password}
            onChange={(event) => setPassword(event.target.value)}
            onKeyDown={(event) => {
              if (event.key === "Enter") onUnlock(password);
            }}
            autoFocus
          />
        </FormField>
        <div className="border-t border-gray-200 pt-4">
          <div className="mb-3 text-sm font-black text-slate-900">비밀번호 설정</div>
          <div className="space-y-3">
            <FormField label="현재 비밀번호" required>
              <input className={modalInputClass} type="password" value={currentPassword} onChange={(event) => setCurrentPassword(event.target.value)} placeholder="현재 비밀번호를 한 번 더 입력" />
            </FormField>
            <div className="grid gap-3 md:grid-cols-2">
              <FormField label="새 비밀번호" required>
                <input className={modalInputClass} type="password" value={newPassword} onChange={(event) => setNewPassword(event.target.value)} />
              </FormField>
              <FormField label="새 비밀번호 확인" required>
                <input className={modalInputClass} type="password" value={confirmPassword} onChange={(event) => setConfirmPassword(event.target.value)} />
              </FormField>
            </div>
            <ActionButton
              type="button"
              variant="secondary"
              onClick={() => {
                if (onChangePassword(currentPassword, newPassword, confirmPassword)) {
                  setCurrentPassword("");
                  setNewPassword("");
                  setConfirmPassword("");
                }
              }}
            >
              비밀번호 수정
            </ActionButton>
          </div>
        </div>
      </div>
    </FormModal>
  );
}

type ChannelProductMappingRow = {
  mallName: string;
  productCode: string;
  productName: string;
  mallProductKey: string;
};

function ChannelProductMappingPanel() {
  const storageKey = "fnos-channel-product-mappings";
  const [rows, setRows] = useState<ChannelProductMappingRow[]>([]);
  const [draft, setDraft] = useState<ChannelProductMappingRow>({ mallName: "", productCode: "", productName: "", mallProductKey: "" });

  useEffect(() => {
    try {
      const saved = JSON.parse(localStorage.getItem(storageKey) || "[]") as ChannelProductMappingRow[];
      setRows(Array.isArray(saved) ? saved : []);
    } catch {
      setRows([]);
    }
  }, []);

  function saveRows(nextRows: ChannelProductMappingRow[]) {
    setRows(nextRows);
    localStorage.setItem(storageKey, JSON.stringify(nextRows));
  }

  function addMapping() {
    if (!draft.mallName || !draft.productCode || !draft.mallProductKey) {
      window.alert("쇼핑몰명, 품목코드, 쇼핑몰품목key를 입력해 주세요.");
      return;
    }
    const nextRows = [
      draft,
      ...rows.filter((row) => !(row.mallName === draft.mallName && row.mallProductKey === draft.mallProductKey)),
    ];
    saveRows(nextRows);
    setDraft({ mallName: "", productCode: "", productName: "", mallProductKey: "" });
  }

  return (
    <Card className="p-4">
      <SectionHeader title="쇼핑몰 코드연결" description="쇼핑몰품목key와 FN OS 품목코드를 연결합니다. 운영 DB 저장은 매핑 테이블 확정 후 연결합니다." />
      <div className="mt-4 grid gap-2 lg:grid-cols-[160px_140px_180px_1fr_88px]">
        <input className={modalInputClass} placeholder="쇼핑몰명" value={draft.mallName} onChange={(event) => setDraft((prev) => ({ ...prev, mallName: event.target.value }))} />
        <input className={modalInputClass} placeholder="품목코드" value={draft.productCode} onChange={(event) => setDraft((prev) => ({ ...prev, productCode: event.target.value }))} />
        <input className={modalInputClass} placeholder="품목명" value={draft.productName} onChange={(event) => setDraft((prev) => ({ ...prev, productName: event.target.value }))} />
        <input className={modalInputClass} placeholder="쇼핑몰품목key" value={draft.mallProductKey} onChange={(event) => setDraft((prev) => ({ ...prev, mallProductKey: event.target.value }))} />
        <ActionButton type="button" onClick={addMapping}>등록</ActionButton>
      </div>
      <div className="mt-4 overflow-x-auto rounded-xl border border-gray-200">
        <table className="w-full min-w-[760px] text-sm">
          <thead className="bg-gray-50 text-xs font-black text-gray-500">
            <tr><th className="px-3 py-2 text-left">쇼핑몰명</th><th className="px-3 py-2 text-left">품목코드</th><th className="px-3 py-2 text-left">품목명</th><th className="px-3 py-2 text-left">쇼핑몰품목key</th><th className="px-3 py-2 text-center">관리</th></tr>
          </thead>
          <tbody>
            {rows.map((row, index) => (
              <tr key={`${row.mallName}-${row.mallProductKey}-${index}`} className="border-t border-gray-100">
                <td className="px-3 py-2 font-semibold">{row.mallName}</td>
                <td className="px-3 py-2">{row.productCode}</td>
                <td className="px-3 py-2">{row.productName}</td>
                <td className="px-3 py-2">{row.mallProductKey}</td>
                <td className="px-3 py-2 text-center"><button type="button" className="text-xs font-black text-rose-600" onClick={() => saveRows(rows.filter((_, rowIndex) => rowIndex !== index))}>삭제</button></td>
              </tr>
            ))}
          </tbody>
        </table>
        {!rows.length && <EmptyState title="연결된 쇼핑몰 코드가 없습니다." />}
      </div>
    </Card>
  );
}

function PersonnelManagementPanel({ onLock }: { onLock: () => void }) {
  const [employees, setEmployees] = useState<PersonnelEmployee[]>([]);
  const [query, setQuery] = useState("");
  const [modalOpen, setModalOpen] = useState(false);
  const [draft, setDraft] = useState<PersonnelEmployee>(blankPersonnelEmployee());
  const [personnelMessage, setPersonnelMessage] = useState("");
  const [selectedKeys, setSelectedKeys] = useState<string[]>([]);
  const [fileEmployee, setFileEmployee] = useState<PersonnelEmployee | null>(null);
  const [fileCounts, setFileCounts] = useState<Record<string, number>>({});
  const [selecting, setSelecting] = useState(false);
  const [bulkOpen, setBulkOpen] = useState(false);
  const [bulkFields, setBulkFields] = useState<PersonnelBulkField[]>(["status"]);
  const [bulkFieldPickerOpen, setBulkFieldPickerOpen] = useState(false);
  const [bulkCommonField, setBulkCommonField] = useState<PersonnelBulkField>("status");
  const [bulkCommonValue, setBulkCommonValue] = useState("");
  const [bulkDrafts, setBulkDrafts] = useState<Record<string, Partial<Record<PersonnelBulkField, string>>>>({});
  const [addressSearchOpen, setAddressSearchOpen] = useState(false);
  const [copiedAddressField, setCopiedAddressField] = useState("");
  const fileInputRef = useRef<HTMLInputElement | null>(null);
  const detailAddressInputRef = useRef<HTMLInputElement | null>(null);
  const selectModeRef = useRef<"select" | "deselect">("select");
  const storageKey = "fnos-personnel-employees";
  const pageSize = 20;

  function blankPersonnelEmployee(): PersonnelEmployee {
    return {
      id: "",
      status: "working",
      role: "staff",
      name: "",
      resident_no: "",
      phone: "",
      address: "",
      postal_code: "",
      road_address: "",
      jibun_address: "",
      detail_address: "",
      email: "",
      joined_at: "",
      department: "",
      rank: "",
      position: "",
      salary: "",
      bank_name: "",
      bank_account_holder: "",
      bank_account_no: "",
      memo: "",
      leave_reason: "",
      leave_from: "",
      leave_to: "",
      leave_memo: "",
      resigned_reason: "",
      resigned_at: "",
      resigned_memo: "",
    };
  }

  function employeeKey(employee: PersonnelEmployee) {
    return employee.id;
  }

  function saveEmployees(nextEmployees: PersonnelEmployee[]) {
    const sorted = sortRowsByManagementName(nextEmployees, (employee) => employee.name, (employee) => employee.resident_no);
    setEmployees(sorted);
    localStorage.setItem(storageKey, JSON.stringify(sorted));
  }

  function filteredEmployees() {
    const needle = query.trim().toLowerCase().replace(/\s+/g, "");
    if (!needle) return employees;
    return employees.filter((employee) => [
      employee.name,
      employee.resident_no,
      employee.phone,
      employee.email,
      employee.address,
      employee.memo,
    ].some((value) => String(value || "").toLowerCase().replace(/\s+/g, "").includes(needle)));
  }

  const visibleEmployees = filteredEmployees().slice(0, pageSize);
  const visibleKeys = visibleEmployees.map(employeeKey).filter(Boolean);
  const selectedEmployees = employees.filter((employee) => selectedKeys.includes(employeeKey(employee)));
  const rowSelection = useCheckboxColumnSelection({ keys: visibleKeys, selectedKeys, setSelectedKeys, enabled: !modalOpen && !bulkOpen && !addressSearchOpen });

  useEffect(() => {
    const saved = JSON.parse(localStorage.getItem(storageKey) || "[]") as PersonnelEmployee[];
    setEmployees(Array.isArray(saved) ? sortRowsByManagementName(saved.map(normalizePersonnelEmployee), (employee) => employee.name, (employee) => employee.resident_no) : []);
  }, []);

  useEffect(() => {
    void loadFnSettingsAttachmentCounts("personnel", employees.map(employeeKey), (counts) => setFileCounts((prev) => ({ ...prev, ...counts })));
  }, [employees]);

  useEffect(() => {
    setSelectedKeys([]);
  }, [query]);

  useEffect(() => {
    function stopSelecting() {
      setSelecting(false);
    }
    window.addEventListener("mouseup", stopSelecting);
    return () => window.removeEventListener("mouseup", stopSelecting);
  }, []);

  useEffect(() => {
    const onKeyDown = (event: globalThis.KeyboardEvent) => {
      if (event.key !== "F2" || modalOpen || bulkOpen || addressSearchOpen) return;
      event.preventDefault();
      openNewEmployee();
    };
    window.addEventListener("keydown", onKeyDown);
    return () => window.removeEventListener("keydown", onKeyDown);
  }, [modalOpen, bulkOpen, addressSearchOpen]);

  function normalizePersonnelEmployee(value: Partial<PersonnelEmployee>): PersonnelEmployee {
    return {
      ...blankPersonnelEmployee(),
      ...value,
      id: value.id || `${Date.now()}-${Math.random().toString(16).slice(2)}`,
      status: normalizePersonnelStatus(value.status),
      role: normalizePersonnelRole(value.role),
      resident_no: formatResidentNo(value.resident_no),
      phone: formatKoreanPhone(value.phone),
      salary: onlyDigits(value.salary),
      address: composePersonnelAddress(value) || String(value.address || ""),
    };
  }

  function openNewEmployee() {
    setDraft(blankPersonnelEmployee());
    setModalOpen(true);
  }

  function openEmployee(employee: PersonnelEmployee) {
    setDraft(normalizePersonnelEmployee(employee));
    setModalOpen(true);
  }

  function updateDraft(key: keyof PersonnelEmployee, value: string) {
    setDraft((prev) => ({
      ...prev,
      [key]: key === "status" ? normalizePersonnelStatus(value) : key === "role" ? normalizePersonnelRole(value) : key === "salary" ? onlyDigits(value) : key === "resident_no" ? formatResidentNo(value) : key === "phone" ? formatKoreanPhone(value) : value,
      ...(key === "detail_address" ? { address: composePersonnelAddress({ ...prev, detail_address: value }) } : {}),
    }));
  }

  function applyPostcode(data: DaumPostcodeData) {
    setDraft((prev) => {
      const next = {
        ...prev,
        postal_code: String(data.zonecode || "").trim(),
        road_address: daumRoadAddressWithExtra(data),
        jibun_address: String(data.jibunAddress || data.autoJibunAddress || "").trim(),
      };
      return { ...next, address: composePersonnelAddress(next) };
    });
    window.setTimeout(() => detailAddressInputRef.current?.focus(), 0);
  }

  async function copyAddressText(value: string, field: string) {
    const text = value.trim();
    if (!text) return;
    try {
      await navigator.clipboard.writeText(text);
      setCopiedAddressField(field);
      window.setTimeout(() => setCopiedAddressField((prev) => prev === field ? "" : prev), 1000);
    } catch {
      window.alert("복사하지 못했습니다. 브라우저 권한을 확인해 주세요.");
    }
  }

  function setSelected(key: string, selected: boolean) {
    if (!key) return;
    setSelectedKeys((prev) => selected ? Array.from(new Set([...prev, key])) : prev.filter((item) => item !== key));
  }

  function validateDraft() {
    if (!draft.status || !draft.role || !draft.name.trim() || !draft.resident_no.trim() || !draft.phone.trim() || !composePersonnelAddress(draft).trim() || !draft.email.trim() || !draft.joined_at.trim() || !draft.salary.trim()) {
      window.alert("속성, 권한, 성명, 주민등록번호, 전화번호, 주소, 이메일, 입사일자, 급여는 필수입니다.");
      return false;
    }
    return true;
  }

  function saveDraft() {
    if (!validateDraft()) return;
    const nextDraft = normalizePersonnelEmployee({ ...draft, address: composePersonnelAddress(draft) });
    const nextEmployees = draft.id
      ? employees.map((employee) => employee.id === draft.id ? nextDraft : employee)
      : [nextDraft, ...employees];
    saveEmployees(nextEmployees);
    setPersonnelMessage(`직원 저장 완료: ${nextDraft.name}`);
    setModalOpen(false);
  }

  function deleteDraft() {
    if (!draft.id) return;
    if (!window.confirm("이 직원을 삭제할까요?")) return;
    saveEmployees(employees.filter((employee) => employee.id !== draft.id));
    setPersonnelMessage(`직원 삭제 완료: ${draft.name}`);
    setModalOpen(false);
  }

  function saveBulkEdit() {
    if (!selectedEmployees.length) {
      window.alert("수정할 직원을 먼저 선택해 주세요.");
      return;
    }
    const nextEmployees = employees.map((employee) => {
      if (!selectedKeys.includes(employee.id)) return employee;
      const draftValues = bulkDrafts[employee.id] || {};
      const updates = Object.fromEntries(bulkFields.map((field) => [
        field,
        field === "status"
          ? normalizePersonnelStatus(draftValues[field] ?? employee[field] ?? "working")
          : field === "role"
            ? normalizePersonnelRole(draftValues[field] ?? employee[field] ?? "staff")
            : field === "salary"
              ? onlyDigits(draftValues[field] ?? employee[field] ?? "")
              : draftValues[field] ?? employee[field] ?? "",
      ]));
      return {
        ...employee,
        ...updates,
      };
    });
    saveEmployees(nextEmployees);
    setSelectedKeys([]);
    setBulkOpen(false);
    setBulkDrafts({});
    setBulkCommonValue("");
    setPersonnelMessage(`선택수정 완료: ${selectedEmployees.length.toLocaleString("ko-KR")}건`);
  }

  function downloadPersonnelTemplate() {
    void downloadTableXlsx(
      "FN_OS_인사_엑셀폼.xlsx",
      "인사",
      ["속성", "권한", "성명", "주민등록번호", "전화번호", "주소", "이메일", "입사일자", "부서", "직급", "직책", "급여", "은행", "예금주", "계좌번호", "메모", "휴직사유", "휴직시작", "휴직종료", "퇴사사유", "퇴사일자"],
      [["근무", "일반 직원", "홍길동", "900101-1234567", "010-0000-0000", "서울", "sample@fnos.local", "2026-06-01", "운영", "대리", "팀원", "3000000", "국민은행", "홍길동", "000000-00-000000", "", "", "", "", "", ""]],
    );
  }

  async function uploadPersonnel(file: File) {
    const rows = await readXlsxObjects(file);
    const normalized = rows.map((row) => normalizePersonnelEmployee({
      status: normalizePersonnelStatus(row["속성"] || row["상태"] || row["구분"]),
      role: normalizePersonnelRole(row["권한"] || row["권환"] || row["관리권한"]),
      name: String(row["성명"] || row["직원명"] || "").trim(),
      resident_no: String(row["주민등록번호"] || row["주민번호"] || "").trim(),
      phone: String(row["전화번호"] || row["연락처"] || "").trim(),
      address: String(row["주소"] || "").trim(),
      email: String(row["이메일"] || row["Email"] || "").trim(),
      joined_at: String(row["입사일자"] || row["입사일"] || "").trim(),
      department: String(row["부서"] || "").trim(),
      rank: String(row["직급"] || "").trim(),
      position: String(row["직책"] || "").trim(),
      salary: onlyDigits(row["급여"] || row["월급"]),
      bank_name: String(row["은행"] || "").trim(),
      bank_account_holder: String(row["예금주"] || "").trim(),
      bank_account_no: String(row["계좌번호"] || "").trim(),
      memo: String(row["메모"] || "").trim(),
      leave_reason: String(row["휴직사유"] || "").trim(),
      leave_from: String(row["휴직시작"] || "").trim(),
      leave_to: String(row["휴직종료"] || "").trim(),
      resigned_reason: String(row["퇴사사유"] || "").trim(),
      resigned_at: String(row["퇴사일자"] || row["퇴사일"] || "").trim(),
    })).filter((employee) => employee.name && employee.resident_no);
    const exactMatches = normalized.filter((row) => employees.some((employee) => employee.name === row.name && employee.resident_no === row.resident_no));
    const overwrite = exactMatches.length
      ? window.confirm(`${exactMatches.length}개 직원의 성명과 주민등록번호가 일치합니다. 현재 엑셀 데이터로 덮어쓰기 하시겠습니까?\n\n확인: 덮어쓰기\n취소: 기존 항목 스킵`)
      : false;
    let saved = 0;
    let skipped = 0;
    const nextEmployees = [...employees];
    normalized.forEach((row) => {
      const index = nextEmployees.findIndex((employee) => employee.name === row.name && employee.resident_no === row.resident_no);
      if (index >= 0 && !overwrite) {
        skipped += 1;
        return;
      }
      if (index >= 0) nextEmployees[index] = { ...row, id: nextEmployees[index].id };
      else nextEmployees.unshift(row);
      saved += 1;
    });
    saveEmployees(nextEmployees);
    setPersonnelMessage(`인사 엑셀등록 완료: 저장 ${saved.toLocaleString("ko-KR")}건 / 스킵 ${skipped.toLocaleString("ko-KR")}건`);
  }

  function downloadPersonnel() {
    const rows = filteredEmployees().map((employee) => [
      personnelStatusLabel(employee.status),
      personnelRoleLabel(employee.role),
      employee.name,
      employee.resident_no,
      employee.phone,
      employee.address,
      employee.email,
      employee.joined_at,
      employee.department,
      employee.rank,
      employee.position,
      onlyDigits(employee.salary),
      employee.bank_name,
      employee.bank_account_holder,
      employee.bank_account_no,
      employee.memo,
      employee.leave_reason || "",
      employee.leave_from || "",
      employee.leave_to || "",
      employee.resigned_reason || "",
      employee.resigned_at || "",
    ]);
    void downloadTableXlsx(`FN_OS_인사_${rows.length}건_${todayMmdd()}.xlsx`, "인사", ["속성", "권한", "성명", "주민등록번호", "전화번호", "주소", "이메일", "입사일자", "부서", "직급", "직책", "급여", "은행", "예금주", "계좌번호", "메모", "휴직사유", "휴직시작", "휴직종료", "퇴사사유", "퇴사일자"], rows);
  }

  return (
    <div className="space-y-4">
      <Panel
        title="인사관리"
        subtitle={<div className="flex flex-wrap items-center gap-3 text-sm font-bold text-slate-500"><button type="button" className="font-black text-orange-600 underline underline-offset-4">전체직원</button><span className="ml-2 rounded-lg bg-slate-100 px-3 py-1 font-black text-slate-900">직원수 {employees.length.toLocaleString("ko-KR")}명</span></div>}
        action={
          <div className="flex flex-wrap gap-2">
            <ActionButton type="button" onClick={openNewEmployee}>F2 새 직원</ActionButton>
            <ActionButton type="button" variant="secondary" onClick={() => fileInputRef.current?.click()}>엑셀등록</ActionButton>
            <ActionButton type="button" variant="secondary" onClick={downloadPersonnel}>인사정보 다운로드</ActionButton>
            <button type="button" onClick={downloadPersonnelTemplate} className="inline-flex h-11 w-11 items-center justify-center rounded-md border-0 bg-transparent p-0 text-emerald-600 hover:bg-orange-50" aria-label="엑셀폼 다운로드" title="엑셀폼 다운로드"><ExcelFormIcon /></button>
            <ActionButton type="button" variant="secondary" onClick={onLock}>잠금</ActionButton>
            <input ref={fileInputRef} type="file" accept=".xlsx,.xls" className="hidden" onChange={(event) => {
              const file = event.target.files?.[0];
              if (file) void uploadPersonnel(file);
              event.target.value = "";
            }} />
          </div>
        }
      >
        <div className="mb-3 flex flex-wrap items-center justify-between gap-2">
          <div className="flex flex-wrap items-center gap-2">
            <ActionButton type="button" variant="secondary" onClick={() => setBulkOpen(true)}>수정</ActionButton>
            <span className="text-xs font-bold text-slate-500">선택 {selectedKeys.length.toLocaleString("ko-KR")}개</span>
          </div>
          <input className="field-input w-full max-w-sm rounded-md border border-slate-200 px-3 py-2 text-sm" value={query} onChange={(event) => setQuery(event.target.value)} placeholder="성명 / 전화번호 / 이메일 검색" />
        </div>
        <div className="fn-table-shell overflow-x-auto [&_td:first-child]:pl-4 [&_td:last-child]:pr-4 [&_th:first-child]:pl-4 [&_th:last-child]:pr-4">
          <table className="w-full min-w-[1100px] table-fixed text-sm">
            <thead className="border-b border-gray-200 bg-gray-50 text-xs font-semibold text-gray-500">
              <tr>
                <th className="w-16 py-2 text-center"><input type="checkbox" className="h-5 w-5" checked={rowSelection.allSelected} onChange={(event) => rowSelection.toggleAll(event.target.checked)} aria-label="직원 전체선택" /></th>
                <th className="w-24 py-2 text-left">속성</th>
                <th className="w-28 py-2 text-left">성명</th>
                <th className="w-40 py-2 text-left">주민등록번호</th>
                <th className="w-36 py-2 text-left">전화번호</th>
                <th className="w-48 py-2 text-left">이메일</th>
                <th className="w-28 py-2 text-left">입사일자</th>
                <th className="w-20 py-2 text-left">파일</th>
                <th className="w-40 py-2 text-left">메모</th>
              </tr>
            </thead>
            <tbody>
              {visibleEmployees.map((employee, index) => {
                const key = employeeKey(employee);
                const selected = selectedKeys.includes(key);
                return (
                  <tr key={key} onClick={() => openEmployee(employee)} className={`cursor-pointer border-b border-gray-100 ${selected ? "bg-sky-50" : "hover:bg-orange-50/60"}`}>
                    <td className="py-2 text-center" onClick={(event) => event.stopPropagation()}>
                      <button
                        type="button"
                        onMouseDown={(event) => {
                          event.preventDefault();
                          const mode = selected ? "deselect" : "select";
                          selectModeRef.current = mode;
                          setSelecting(true);
                          setSelected(key, mode === "select");
                        }}
                        onMouseEnter={() => {
                          if (selecting) setSelected(key, selectModeRef.current === "select");
                        }}
                        className={`inline-flex h-6 min-w-6 items-center justify-center rounded px-1 text-xs font-black ${selected ? "bg-blue-600 text-white" : "border border-gray-300 bg-white text-gray-400"}`}
                      >
                        {index + 1}
                      </button>
                    </td>
                    <td className="truncate py-2"><StatusBadge tone={employee.status === "working" ? "success" : employee.status === "leave" ? "orange" : "muted"}>{personnelStatusLabel(employee.status)}</StatusBadge></td>
                    <td className="truncate py-2 font-bold">{employee.name || "-"}</td>
                    <td className="truncate py-2 text-slate-600">{employee.resident_no || "-"}</td>
                    <td className="truncate py-2 text-slate-600">{employee.phone || "-"}</td>
                    <td className="truncate py-2 text-slate-600">{employee.email || "-"}</td>
                    <td className="truncate py-2 text-slate-600">{employee.joined_at || "-"}</td>
                    <td className="py-2" onClick={(event) => event.stopPropagation()}>
                      <FolderAttachmentButton count={fileCounts[key]} title="직원 첨부파일" onClick={() => setFileEmployee(employee)} />
                    </td>
                    <td className="truncate py-2 text-slate-500" title={employee.memo || ""}>{employee.memo ? `${employee.memo.slice(0, 10)}${employee.memo.length > 10 ? "..." : ""}` : "-"}</td>
                  </tr>
                );
              })}
            </tbody>
          </table>
          {!visibleEmployees.length && <EmptyState title="등록된 직원이 없습니다." />}
        </div>
      </Panel>

      {fileEmployee && (
        <AccountFileModal
          accountType="personnel"
          accountId={employeeKey(fileEmployee)}
          title={fileEmployee.name || "직원"}
          onClose={() => setFileEmployee(null)}
          onChanged={(count) => setFileCounts((prev) => ({ ...prev, [employeeKey(fileEmployee)]: count }))}
        />
      )}

      {bulkOpen && (
        <BulkMultiEditModal<PersonnelBulkField, PersonnelEmployee>
          title="직원 선택수정"
          description={`선택 ${selectedEmployees.length.toLocaleString("ko-KR")}개 직원의 값을 수정합니다.`}
          fields={personnelBulkFields}
          selectedFields={bulkFields}
          setSelectedFields={setBulkFields}
          fieldPickerOpen={bulkFieldPickerOpen}
          setFieldPickerOpen={setBulkFieldPickerOpen}
          commonField={bulkCommonField}
          setCommonField={setBulkCommonField}
          commonValue={bulkCommonValue}
          setCommonValue={setBulkCommonValue}
          rowDrafts={bulkDrafts}
          setRowDrafts={setBulkDrafts}
          rows={selectedEmployees}
          rowKeys={selectedEmployees.map((employee) => employee.id)}
          selectedRowKeys={selectedKeys}
          setSelectedRowKeys={setSelectedKeys}
          getRowKey={(employee) => employee.id}
          getRowName={(employee) => employee.name || "-"}
          getRowSubLabel={(employee) => employee.resident_no || employee.phone || "-"}
          getCurrentValue={(employee, field) => {
            if (field === "status") return normalizePersonnelStatus(employee.status);
            if (field === "role") return normalizePersonnelRole(employee.role);
            if (field === "salary") return onlyDigits(employee.salary);
            return String(employee[field] || "");
          }}
          onClose={() => setBulkOpen(false)}
          onSave={saveBulkEdit}
        />
      )}

      {modalOpen && (
        <FormModal
          title={draft.id ? "직원 수정" : "새 직원 등록"}
          description="필수 항목은 빨간 별표로 표시됩니다."
          onClose={() => setModalOpen(false)}
          size="xl"
          footer={<><div className="mr-auto">{draft.id && <ActionButton type="button" variant="danger" onClick={deleteDraft}>삭제</ActionButton>}</div><ActionButton type="button" variant="secondary" onClick={() => setModalOpen(false)}>닫기</ActionButton><ActionButton type="button" onClick={saveDraft}>저장</ActionButton></>}
        >
          <div className="space-y-5">
            <div className="grid gap-4 md:grid-cols-2">
              <div>
                <div className="mb-2 text-[13px] font-semibold text-gray-700">속성 <span className="text-[#ff6a00]">*</span></div>
                <div className="flex flex-wrap gap-2">
                  {[
                    ["working", "근무"],
                    ["leave", "휴직"],
                    ["resigned", "퇴사"],
                  ].map(([value, label]) => (
                    <button key={value} type="button" onClick={() => updateDraft("status", value)} className={`h-10 rounded-md px-4 text-sm font-black ${draft.status === value ? "bg-orange-500 text-white" : "border border-gray-200 bg-white text-slate-600 hover:bg-orange-50"}`}>{label}</button>
                  ))}
                </div>
              </div>
              <div>
                <div className="mb-2 text-[13px] font-semibold text-gray-700">권한 <span className="text-[#ff6a00]">*</span></div>
                <div className="flex flex-wrap gap-2">
                  {[
                    ["staff", "일반 직원"],
                    ["admin", "관리자"],
                  ].map(([value, label]) => (
                    <button key={value} type="button" onClick={() => updateDraft("role", value)} className={`h-10 rounded-md px-4 text-sm font-black ${draft.role === value ? "bg-orange-500 text-white" : "border border-gray-200 bg-white text-slate-600 hover:bg-orange-50"}`}>{label}</button>
                  ))}
                </div>
              </div>
            </div>
            <div className="grid gap-4 md:grid-cols-2">
              <FormField label="성명" required><input className={modalInputClass} value={draft.name} onChange={(event) => updateDraft("name", event.target.value)} /></FormField>
              <FormField label="주민등록번호" required><input className={modalInputClass} inputMode="numeric" value={draft.resident_no} onChange={(event) => updateDraft("resident_no", event.target.value)} placeholder="900101-1234567" maxLength={14} /></FormField>
              <FormField label="전화번호" required><input className={modalInputClass} inputMode="numeric" value={draft.phone} onChange={(event) => updateDraft("phone", event.target.value)} placeholder="010-0000-0000" maxLength={13} /></FormField>
              <FormField label="이메일" required><input className={modalInputClass} value={draft.email} onChange={(event) => updateDraft("email", event.target.value)} placeholder="name@example.com" /></FormField>
              <FormField label="주소" required className="md:col-span-2">
                <div className="grid gap-2">
                  <div className="grid gap-2 md:grid-cols-[120px_180px_1fr]">
                    <ActionButton type="button" variant="secondary" onClick={() => setAddressSearchOpen(true)}>주소검색</ActionButton>
                    <div className="relative">
                      <input className={`${modalInputClass} pr-10`} value={draft.postal_code || ""} readOnly placeholder="우편번호" />
                      <button type="button" onClick={() => void copyAddressText(String(draft.postal_code || ""), "postal")} className="absolute right-1 top-1 inline-flex h-8 w-8 items-center justify-center rounded-md text-slate-500 hover:bg-orange-50 hover:text-orange-600" title="우편번호 복사" aria-label="우편번호 복사">
                        <svg viewBox="0 0 24 24" className="h-4 w-4" aria-hidden="true" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                          <rect x="9" y="9" width="13" height="13" rx="2" />
                          <path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1" />
                        </svg>
                      </button>
                      {copiedAddressField === "postal" && <span className="absolute right-0 top-full z-20 mt-1 whitespace-nowrap rounded-md bg-slate-900 px-2 py-1 text-[11px] font-black text-white shadow-lg">복사되었습니다.</span>}
                    </div>
                    <input ref={detailAddressInputRef} className={modalInputClass} value={draft.detail_address || ""} onChange={(event) => updateDraft("detail_address", event.target.value)} placeholder="상세주소" />
                  </div>
                  <div className="grid gap-2 md:grid-cols-[1fr_40px]">
                    <input className={modalInputClass} value={composePersonnelAddress(draft)} readOnly placeholder="주소" />
                    <div className="relative">
                      <button type="button" onClick={() => void copyAddressText(composePersonnelAddress(draft), "address")} className="inline-flex h-10 w-10 items-center justify-center rounded-lg border border-gray-300 bg-white text-slate-500 hover:bg-orange-50 hover:text-orange-600" title="주소 복사" aria-label="주소 복사">
                        <svg viewBox="0 0 24 24" className="h-4 w-4" aria-hidden="true" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                          <rect x="9" y="9" width="13" height="13" rx="2" />
                          <path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1" />
                        </svg>
                      </button>
                      {copiedAddressField === "address" && <span className="absolute right-0 top-full z-20 mt-1 whitespace-nowrap rounded-md bg-slate-900 px-2 py-1 text-[11px] font-black text-white shadow-lg">복사되었습니다.</span>}
                    </div>
                  </div>
                </div>
              </FormField>
              <FormField label="입사일자" required>
                <div className="grid gap-2 md:grid-cols-[1fr_auto]">
                  <input className={modalInputClass} type="date" value={draft.joined_at} onChange={(event) => updateDraft("joined_at", event.target.value)} />
                  {draft.status === "working" && draft.joined_at && (
                    <div className="flex h-10 items-center rounded-md border border-orange-100 bg-orange-50 px-3 text-sm font-black text-orange-600">
                      {personnelWorkingMonths(draft.joined_at)}
                    </div>
                  )}
                </div>
              </FormField>
              <div className="grid gap-2 md:grid-cols-3">
                <FormField label="부서"><input className={modalInputClass} value={draft.department} onChange={(event) => updateDraft("department", event.target.value)} /></FormField>
                <FormField label="직급"><input className={modalInputClass} value={draft.rank} onChange={(event) => updateDraft("rank", event.target.value)} /></FormField>
                <FormField label="직책"><input className={modalInputClass} value={draft.position} onChange={(event) => updateDraft("position", event.target.value)} /></FormField>
              </div>
              <div className="grid gap-2 md:col-span-2 md:grid-cols-4">
                <FormField label="급여" required><input className={modalInputClass} inputMode="numeric" value={formatCommaNumber(draft.salary)} onChange={(event) => updateDraft("salary", event.target.value)} placeholder="3,000,000" /></FormField>
                <FormField label="은행"><input className={modalInputClass} value={draft.bank_name} onChange={(event) => updateDraft("bank_name", event.target.value)} /></FormField>
                <FormField label="예금주"><input className={modalInputClass} value={draft.bank_account_holder} onChange={(event) => updateDraft("bank_account_holder", event.target.value)} /></FormField>
                <FormField label="계좌번호"><input className={modalInputClass} value={draft.bank_account_no} onChange={(event) => updateDraft("bank_account_no", event.target.value)} /></FormField>
              </div>
              <FormField label="메모" className="md:col-span-2"><textarea className={modalTextareaClass} value={draft.memo} onChange={(event) => updateDraft("memo", event.target.value)} /></FormField>
            </div>
            {draft.status === "leave" && (
              <div className="grid gap-4 border-t border-gray-200 pt-4 md:grid-cols-2">
                <div className="md:col-span-2 text-sm font-black text-slate-900">휴직 정보</div>
                <FormField label="휴직 사유"><input className={modalInputClass} value={draft.leave_reason || ""} onChange={(event) => updateDraft("leave_reason", event.target.value)} /></FormField>
                <div className="grid gap-2 md:grid-cols-2">
                  <FormField label="휴직 시작"><input className={modalInputClass} type="date" value={draft.leave_from || ""} onChange={(event) => updateDraft("leave_from", event.target.value)} /></FormField>
                  <FormField label="휴직 종료"><input className={modalInputClass} type="date" value={draft.leave_to || ""} onChange={(event) => updateDraft("leave_to", event.target.value)} /></FormField>
                </div>
                <FormField label="메모" className="md:col-span-2"><textarea className={modalTextareaClass} value={draft.leave_memo || ""} onChange={(event) => updateDraft("leave_memo", event.target.value)} /></FormField>
              </div>
            )}
            {draft.status === "resigned" && (
              <div className="grid gap-4 border-t border-gray-200 pt-4 md:grid-cols-2">
                <div className="md:col-span-2 text-sm font-black text-slate-900">퇴사 정보</div>
                <FormField label="퇴사 사유"><input className={modalInputClass} value={draft.resigned_reason || ""} onChange={(event) => updateDraft("resigned_reason", event.target.value)} /></FormField>
                <FormField label="퇴사일자"><input className={modalInputClass} type="date" value={draft.resigned_at || ""} onChange={(event) => updateDraft("resigned_at", event.target.value)} /></FormField>
                <FormField label="메모" className="md:col-span-2"><textarea className={modalTextareaClass} value={draft.resigned_memo || ""} onChange={(event) => updateDraft("resigned_memo", event.target.value)} /></FormField>
              </div>
            )}
          </div>
        </FormModal>
      )}

      {addressSearchOpen && <DaumPostcodeModal onClose={() => setAddressSearchOpen(false)} onSelect={applyPostcode} />}
    </div>
  );
}

function CustomerManagementPanel({ setMessage }: { message: string; setMessage: (value: string) => void }) {
  const pageSize = 20;
  const initialCustomerEndpoint = `/api/fnos/customers?${new URLSearchParams({ page: "1", pageSize: String(pageSize), relation: "general" }).toString()}`;
  const initialCustomerData = readInitialCachedJson<{ customers?: FnCustomer[]; total?: number; ok?: boolean; error?: string }>(initialCustomerEndpoint, { storageTtl: 5 * 60_000 });
  const [customers, setCustomers] = useState<FnCustomer[]>(initialCustomerData?.customers || []);
  const [query, setQuery] = useState("");
  const [relationFilter, setRelationFilter] = useState<CustomerRelationFilter>("general");
  const [page, setPage] = useState(1);
  const [total, setTotal] = useState(Number(initialCustomerData?.total || 0));
  const [loading, setLoading] = useState(!initialCustomerData);
  const [modalOpen, setModalOpen] = useState(false);
  const [draft, setDraft] = useState<Record<string, string>>({});
  const [channelDraft, setChannelDraft] = useState<SalesChannelDraft>(blankSalesChannelDraft());
  const [channelCredentials, setChannelCredentials] = useState(blankSalesChannelCredentials());
  const [credentialMeta, setCredentialMeta] = useState<Record<string, SalesChannelCredentialMeta>>({});
  const [credentialsRevealed, setCredentialsRevealed] = useState(false);
  const [channelLoading, setChannelLoading] = useState(false);
  const [customerMessage, setCustomerMessage] = useState("");
  const [selectedCustomerKeys, setSelectedCustomerKeys] = useState<string[]>([]);
  const [customerSelecting, setCustomerSelecting] = useState(false);
  const [customerBulkOpen, setCustomerBulkOpen] = useState(false);
  const [customerBulkSelectedFields, setCustomerBulkSelectedFields] = useState<CustomerBulkField[]>(["customer_type"]);
  const [customerBulkFieldPickerOpen, setCustomerBulkFieldPickerOpen] = useState(false);
  const [customerBulkCommonField, setCustomerBulkCommonField] = useState<CustomerBulkField>("customer_type");
  const [customerBulkCommonValue, setCustomerBulkCommonValue] = useState("");
  const [customerBulkDrafts, setCustomerBulkDrafts] = useState<Record<string, Partial<Record<CustomerBulkField, string>>>>({});
  const [customerFile, setCustomerFile] = useState<FnCustomer | null>(null);
  const [customerFileCounts, setCustomerFileCounts] = useState<Record<string, number>>({});
  const fileInputRef = useRef<HTMLInputElement | null>(null);
  const customerSelectModeRef = useRef<"select" | "deselect">("select");
  const pageCount = Math.max(1, Math.ceil(total / pageSize));
  const customerKeys = customers.map((customer) => customer.id || customer.customer_code || customer.cust_code || "").filter(Boolean);
  const selectedCustomers = customers.filter((customer) => selectedCustomerKeys.includes(customer.id || customer.customer_code || customer.cust_code || ""));
  const customerSelection = useCheckboxColumnSelection({ keys: customerKeys, selectedKeys: selectedCustomerKeys, setSelectedKeys: setSelectedCustomerKeys, enabled: !modalOpen && !customerBulkOpen });

  function blankCustomerDraft() {
    return { id: "", customer_code: "", customer_name: "", customer_type: "general", business_no: "", fax: "", contact_name: "", phone: "", email: "", postal_code: "", road_address: "", jibun_address: "", detail_address: "", address: "", payment_terms: "", memo: "" };
  }

  async function loadCustomers(nextPage = page, nextQuery = query, nextRelation = relationFilter) {
    setLoading(true);
    try {
      const params = new URLSearchParams({ page: String(nextPage), pageSize: String(pageSize) });
      if (nextQuery.trim()) params.set("q", nextQuery.trim());
      if (nextRelation !== "all") params.set("relation", nextRelation);
      const endpoint = `/api/fnos/customers?${params.toString()}`;
      const cached = readCachedJson<{ customers?: FnCustomer[]; total?: number; ok?: boolean; error?: string }>(endpoint, { storageTtl: 5 * 60_000 });
      if (cached) {
        setCustomers(sortRowsByManagementName(cached.customers || [], (customer) => customer.customer_name || customer.cust_name, (customer) => customer.customer_code || customer.cust_code));
        setTotal(Number(cached.total || 0));
        setLoading(false);
      }
      const data = await cachedClientJson<{ customers?: FnCustomer[]; total?: number; ok?: boolean; error?: string }>(endpoint, { ttl: 5 * 60_000, storageTtl: 10 * 60_000 });
      if (data.ok === false) {
        setCustomerMessage(data.error || "거래처 조회 실패");
        return;
      }
      setCustomers(sortRowsByManagementName(data.customers || [], (customer) => customer.customer_name || customer.cust_name, (customer) => customer.customer_code || customer.cust_code));
      setTotal(Number(data.total || 0));
    } finally {
      setLoading(false);
    }
  }

  useEffect(() => {
    const timer = window.setTimeout(() => void loadCustomers(page, query, relationFilter), 0);
    return () => window.clearTimeout(timer);
  }, [page, query, relationFilter]);

  useEffect(() => {
    setSelectedCustomerKeys([]);
  }, [page, query, relationFilter]);

  useEffect(() => {
    void loadFnSettingsAttachmentCounts("customer", customers.map(customerRowKey), (counts) => setCustomerFileCounts((prev) => ({ ...prev, ...counts })));
  }, [customers]);

  useEffect(() => {
    function stopSelecting() {
      setCustomerSelecting(false);
    }
    window.addEventListener("mouseup", stopSelecting);
    return () => window.removeEventListener("mouseup", stopSelecting);
  }, []);

  useEffect(() => {
    const onKeyDown = (event: globalThis.KeyboardEvent) => {
      if (event.key !== "F2") return;
      event.preventDefault();
      openNewCustomer();
    };
    window.addEventListener("keydown", onKeyDown);
    return () => window.removeEventListener("keydown", onKeyDown);
  }, []);

  function openNewCustomer() {
    const nextDraft = blankCustomerDraft();
    setDraft(nextDraft);
    setChannelDraft(blankSalesChannelDraft(nextDraft));
    setChannelCredentials(blankSalesChannelCredentials());
    setCredentialMeta({});
    setCredentialsRevealed(false);
    setModalOpen(true);
  }

  function openCustomer(customer: FnCustomer) {
    const nextDraft = {
      id: customer.id || "",
      customer_code: customer.customer_code || customer.cust_code || "",
      customer_name: customer.customer_name || customer.cust_name || "",
      customer_type: normalizeCustomerAttribute(customer.customer_type || customer.customer_type_label),
      business_no: formatBusinessNoInput(customer.business_no || ""),
      fax: customer.fax || "",
      contact_name: customer.contact_name || "",
      phone: customer.phone || "",
      email: customer.email || "",
      postal_code: "",
      road_address: customer.address || "",
      jibun_address: "",
      detail_address: "",
      address: customer.address || "",
      payment_terms: customer.payment_terms || "",
      memo: customer.memo || "",
    };
    setDraft(nextDraft);
    setChannelDraft(blankSalesChannelDraft(nextDraft));
    setChannelCredentials(blankSalesChannelCredentials());
    setCredentialMeta({});
    setCredentialsRevealed(false);
    setModalOpen(true);
    if (normalizeCustomerAttribute(nextDraft.customer_type) === "shopping") void loadCustomerChannel(nextDraft);
  }

  function updateDraft(key: string, value: string) {
    setDraft((prev) => {
      if (key === "customer_type") return { ...prev, customer_type: normalizeCustomerAttribute(value) };
      if (key === "business_no") return { ...prev, business_no: formatBusinessNoInput(value) };
      if (key === "phone") return { ...prev, phone: formatKoreanPhone(value) };
      if (key === "fax") return { ...prev, fax: formatKoreanLandline(value) };
      if (key === "customer_code") {
        const previousCodeBusinessNo = formatBusinessNoInput(prev.customer_code || "");
        const shouldSyncBusinessNo = Boolean(prev.business_no && prev.business_no === previousCodeBusinessNo);
        setChannelDraft((channel) => ({
          ...channel,
          channel_code: channel.id ? channel.channel_code : value.trim().toUpperCase(),
        }));
        return {
          ...prev,
          customer_code: value,
          business_no: shouldSyncBusinessNo ? formatBusinessNoInput(value) : prev.business_no,
        };
      }
      if (key === "customer_name") {
        setChannelDraft((channel) => ({
          ...channel,
          channel_name: channel.id ? channel.channel_name : value,
        }));
      }
      if (key === "road_address" || key === "jibun_address" || key === "detail_address" || key === "address") {
        const next = { ...prev, [key]: value };
        return { ...next, address: composeCustomerAddress(next) };
      }
      return { ...prev, [key]: value };
    });
  }

  function updateChannelDraft(key: string, value: string) {
    setChannelDraft((prev) => ({ ...prev, [key]: key === "channel_code" ? value.trim().toUpperCase() : value }));
  }

  function updateChannelCredential(key: string, value: string) {
    setChannelCredentials((prev) => ({ ...prev, [key]: value }));
  }

  function customerRowKey(customer: FnCustomer) {
    return customer.id || customer.customer_code || customer.cust_code || "";
  }

  function setCustomerSelected(key: string, selected: boolean) {
    if (!key) return;
    setSelectedCustomerKeys((prev) => selected ? Array.from(new Set([...prev, key])) : prev.filter((item) => item !== key));
  }

  function toggleCustomerSelected(key: string) {
    if (!key) return;
    setSelectedCustomerKeys((prev) => prev.includes(key) ? prev.filter((item) => item !== key) : [...prev, key]);
  }

  async function loadCustomerChannel(customer: Record<string, string>) {
    setChannelLoading(true);
    setCredentialsRevealed(false);
    try {
      const data = await cachedClientJson<{ channels?: SalesChannelRow[]; ok?: boolean; error?: string }>("/api/fnos/sales-channels", { ttl: 5 * 60_000, storageTtl: 10 * 60_000 });
      if (data.ok === false) {
        setCustomerMessage(data.error || "쇼핑몰 채널 조회 실패");
        return;
      }
      const channels = (data.channels || []) as SalesChannelRow[];
      const channel = channels.find((item) => (
        (customer.id && String(item.customer_id || "") === customer.id) ||
        (customer.customer_code && String(item.customer_code || "").trim() === customer.customer_code) ||
        (customer.customer_name && String(item.customer_name || "").trim() === customer.customer_name)
      ));
      setChannelDraft(normalizeSalesChannelDraft(channel, customer));
      const meta = Object.fromEntries((channel?.credentials || []).map((item) => [item.key, item]));
      setCredentialMeta(meta);
      setChannelCredentials(blankSalesChannelCredentials());
    } finally {
      setChannelLoading(false);
    }
  }

  async function revealChannelCredentials() {
    if (credentialsRevealed) {
      setCredentialsRevealed(false);
      setChannelCredentials(blankSalesChannelCredentials());
      return;
    }
    const channelId = String(channelDraft.id || "").trim();
    if (!channelId) {
      setCustomerMessage("먼저 쇼핑몰 채널을 저장한 뒤 secret 값을 볼 수 있습니다.");
      return;
    }
    setChannelLoading(true);
    try {
      const res = await fetch(`/api/fnos/sales-channel-credentials?channel_id=${encodeURIComponent(channelId)}&reveal=true`, { cache: "no-store", credentials: "include" });
      const data = await res.json().catch(() => ({}));
      if (!res.ok || data.ok === false) {
        setCustomerMessage(data.error || "쇼핑몰 credential 조회 실패");
        return;
      }
      const next = blankSalesChannelCredentials();
      const nextMeta: Record<string, SalesChannelCredentialMeta> = {};
      (data.credentials || []).forEach((item: SalesChannelCredentialMeta & { value?: string }) => {
        if (salesChannelCredentialKeys.includes(item.key as (typeof salesChannelCredentialKeys)[number])) {
          next[item.key as (typeof salesChannelCredentialKeys)[number]] = String(item.value || "");
          nextMeta[item.key] = item;
        }
      });
      setCredentialMeta((prev) => ({ ...prev, ...nextMeta }));
      setChannelCredentials(next);
      setCredentialsRevealed(true);
    } finally {
      setChannelLoading(false);
    }
  }

  async function saveCustomerDraft() {
    const code = String(draft.customer_code || "").trim();
    const name = String(draft.customer_name || "").trim();
    const type = normalizeCustomerAttribute(draft.customer_type);
    if (!type || !code || !name) {
      window.alert("속성, 거래처코드, 거래처명은 필수입니다.");
      return;
    }
    const res = await fetch("/api/fnos/customers", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      credentials: "include",
      body: JSON.stringify({ customer: draft }),
    });
    const data = await res.json().catch(() => ({}));
    if (!res.ok || data.ok === false) {
      window.alert(data.error || "거래처 저장 실패");
      return;
    }
    invalidateClientCache("/api/fnos/customers");
    const savedCustomer = data.customer || {};
    if (normalizeCustomerAttribute(draft.customer_type) === "shopping") {
      const channelPayload = {
        ...channelDraft,
        channel_code: (channelDraft.channel_code || code).trim().toUpperCase(),
        channel_name: (channelDraft.channel_name || name).trim(),
        customer_id: savedCustomer.id || draft.id || null,
        customer_code: code,
        customer_name: name,
        api_enabled: channelDraft.api_enabled === "true",
      };
      const channelRes = await fetch("/api/fnos/sales-channels", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        credentials: "include",
        body: JSON.stringify(channelPayload),
      });
      const channelData = await channelRes.json().catch(() => ({}));
      if (!channelRes.ok || channelData.ok === false) {
        window.alert(channelData.error || "쇼핑몰 채널 저장 실패");
        return;
      }
      invalidateClientCache("/api/fnos/sales-channels");
      const savedChannel = (channelData.channels || [])[0] as SalesChannelRow | undefined;
      const channelId = String(savedChannel?.id || channelDraft.id || "");
      const credentialPayload = Object.fromEntries(
        salesChannelCredentialKeys
          .map((key) => [key, String(channelCredentials[key] || "").trim()] as const)
          .filter(([, value]) => value !== "")
      );
      if (channelId && Object.keys(credentialPayload).length) {
        const credentialRes = await fetch("/api/fnos/sales-channel-credentials", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          credentials: "include",
          body: JSON.stringify({ channel_id: channelId, credentials: credentialPayload }),
        });
        const credentialData = await credentialRes.json().catch(() => ({}));
        if (!credentialRes.ok || credentialData.ok === false) {
          window.alert(credentialData.error || "쇼핑몰 credential 저장 실패");
          return;
        }
        invalidateClientCache("/api/fnos/sales-channel-credentials");
      }
    }
    setCustomerMessage(`거래처 저장 완료: ${code}`);
    setMessage("");
    setModalOpen(false);
    await loadCustomers(page, query, relationFilter);
  }

  async function deleteCustomerDraft() {
    const id = String(draft.id || "").trim();
    const code = String(draft.customer_code || "").trim();
    if (!id && !code) return;
    if (!window.confirm("이 거래처를 삭제할까요?")) return;
    const res = await fetch("/api/fnos/customers", {
      method: "DELETE",
      headers: { "Content-Type": "application/json" },
      credentials: "include",
      body: JSON.stringify({ id, customer_code: code }),
    });
    const data = await res.json().catch(() => ({}));
    if (!res.ok || data.ok === false) {
      setCustomerMessage(data.error || "거래처 삭제 실패");
      return;
    }
    invalidateClientCache("/api/fnos/customers");
    invalidateClientCache("/api/fnos/sales-channels");
    setCustomerMessage(`거래처 삭제 완료: ${code}`);
    setModalOpen(false);
    await loadCustomers(page, query, relationFilter);
  }

  async function saveCustomerBulkEdit() {
    if (!selectedCustomers.length) {
      setCustomerMessage("수정할 거래처를 먼저 선택해 주세요.");
      return;
    }
    let saved = 0;
    for (const customer of selectedCustomers) {
      const key = customerRowKey(customer);
      const draftValues = customerBulkDrafts[key] || {};
      const updates = Object.fromEntries(customerBulkSelectedFields.map((field) => {
        const rawValue = draftValues[field] ?? String(customer[field as keyof FnCustomer] || "");
        const value = field === "customer_type" ? normalizeCustomerAttribute(rawValue) : field === "business_no" ? formatBusinessNoInput(rawValue) : rawValue;
        return [field, value];
      }));
      const payload = {
        id: customer.id,
        customer_code: customer.customer_code || customer.cust_code || "",
        customer_name: customer.customer_name || customer.cust_name || "",
        customer_type: normalizeCustomerAttribute(customer.customer_type || customer.customer_type_label),
        business_no: customer.business_no || "",
        contact_name: customer.contact_name || "",
        phone: customer.phone || "",
        fax: customer.fax || "",
        email: customer.email || "",
        address: customer.address || "",
        payment_terms: customer.payment_terms || "",
        memo: customer.memo || "",
        ...updates,
      };
      const res = await fetch("/api/fnos/customers", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        credentials: "include",
        body: JSON.stringify({ customer: payload }),
      });
      if (res.ok) saved += 1;
    }
    setCustomerMessage(`선택수정 완료: ${saved.toLocaleString("ko-KR")}건`);
    setCustomerBulkOpen(false);
    setCustomerBulkDrafts({});
    setCustomerBulkCommonValue("");
    setSelectedCustomerKeys([]);
    invalidateClientCache("/api/fnos/customers");
    await loadCustomers(page, query, relationFilter);
  }

  function downloadCustomerTemplate() {
    void downloadTableXlsx(
      "FN_OS_거래처_엑셀폼.xlsx",
      "거래처",
      ["속성", "거래처코드", "거래처명", "사업자번호", "담당자", "전화번호", "주소/Email/기타메모"],
      [["일반", "CUST001", "샘플거래처", "1111111111", "담당자", "010-0000-0000", "주소: 서울 / Email: sample@fnos.local"]],
    );
  }

  async function uploadCustomers(file: File) {
    const rows = await readXlsxObjects(file);
    const allData = await cachedClientJson<{ customers?: FnCustomer[] }>("/api/fnos/customers?page=1&pageSize=5000", { ttl: 60_000, storageTtl: 5 * 60_000 });
    const existing = new Map<string, FnCustomer>((allData.customers || []).map((customer: FnCustomer) => [String(customer.customer_code || customer.cust_code || ""), customer]));
    const normalized = rows
      .map((row) => ({
        customer_type: normalizeCustomerAttribute(row["속성"] || row["거래처속성"] || row["거래처구분"] || row["구분"]),
        customer_code: String(row["거래처코드"] || row["거래처 코드"] || row["코드"] || row["customer_code"] || "").trim(),
        customer_name: String(row["거래처명"] || row["거래처명칭"] || row["상호"] || row["customer_name"] || "").trim(),
        business_no: formatBusinessNoInput(String(row["사업자번호"] || row["사업자등록번호"] || "").trim()),
        contact_name: String(row["담당자"] || row["연락담당자"] || "").trim(),
        phone: String(row["전화번호"] || row["전화"] || row["연락처"] || row["휴대폰"] || "").trim(),
        fax: String(row["팩스번호"] || row["팩스"] || row["FAX"] || "").trim(),
        email: String(row["이메일"] || row["Email"] || row["E-mail"] || row["EMAIL"] || "").trim(),
        address: String(row["주소"] || row["거래처주소"] || "").trim(),
        memo: String(row["주소/Email/기타메모"] || row["거래처정보"] || row["기타메모"] || row["메모"] || row["비고"] || "").trim(),
      }))
      .filter((row) => row.customer_code && row.customer_name);
    const exactMatches = normalized.filter((row) => {
      const found = existing.get(row.customer_code);
      return found && String(found.customer_name || found.cust_name || "").trim() === row.customer_name;
    });
    const overwrite = exactMatches.length
      ? window.confirm(`${exactMatches.length}개 거래처의 거래처코드와 거래처명이 일치합니다. 현재 엑셀 데이터로 덮어쓰기 하시겠습니까?\n\n확인: 덮어쓰기\n취소: 기존 항목 스킵`)
      : false;
    let saved = 0;
    let skipped = 0;
    for (const row of normalized) {
      const found = existing.get(row.customer_code);
      if (found && !overwrite) {
        skipped += 1;
        continue;
      }
      if (found && String(found.customer_name || found.cust_name || "").trim() !== row.customer_name) {
        skipped += 1;
        continue;
      }
      const res = await fetch("/api/fnos/customers", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        credentials: "include",
        body: JSON.stringify({ customer: { ...row, id: found?.id } }),
      });
      if (res.ok) saved += 1;
    }
    setCustomerMessage(`거래처 엑셀등록 완료: 저장 ${saved.toLocaleString("ko-KR")}건 / 스킵 ${skipped.toLocaleString("ko-KR")}건`);
    invalidateClientCache("/api/fnos/customers");
    await loadCustomers(1, query, relationFilter);
    setPage(1);
  }

  async function downloadCustomers() {
    const params = new URLSearchParams({ page: "1", pageSize: "5000" });
    if (query.trim()) params.set("q", query.trim());
    if (relationFilter !== "all") params.set("relation", relationFilter);
    const data = await cachedClientJson<{ customers?: FnCustomer[]; ok?: boolean; error?: string }>(`/api/fnos/customers?${params.toString()}`, { ttl: 60_000, storageTtl: 5 * 60_000 }).catch((error) => ({ ok: false, error: error instanceof Error ? error.message : "거래처 다운로드 실패", customers: [] }));
    if (data.ok === false) {
      setCustomerMessage(data.error || "거래처 다운로드 실패");
      return;
    }
    const rows = ((data.customers || []) as FnCustomer[]).map((customer) => [
      customer.customer_code || customer.cust_code || "",
      customer.customer_name || customer.cust_name || "",
      customerAttributeLabel(customer.customer_type || customer.customer_type_label),
      customer.business_no || "",
      customer.contact_name || "",
      customer.phone || "",
      customer.address || "",
      customer.memo || "",
    ]);
    void downloadTableXlsx(`FN_OS_거래처_${rows.length}건_${todayMmdd()}.xlsx`, "거래처", ["거래처코드", "거래처명", "속성", "사업자번호", "담당자", "전화번호", "주소", "주소/Email/기타메모"], rows);
  }

  const pageNumbers = Array.from({ length: Math.min(6, pageCount) }, (_, index) => {
    const start = Math.min(Math.max(1, page - 2), Math.max(1, pageCount - 5));
    return start + index;
  }).filter((value) => value <= pageCount);

  return (
    <div className="space-y-4">
      <Panel
        title="거래처 관리"
        subtitle={
          <div className="flex flex-wrap items-center gap-3 text-sm font-bold text-slate-500">
            {[
              { key: "general" as CustomerRelationFilter, label: "일반" },
              { key: "shopping" as CustomerRelationFilter, label: "쇼핑몰" },
              { key: "all" as CustomerRelationFilter, label: "전체거래처" },
            ].map((filter) => (
              <button
                key={filter.key}
                type="button"
                onClick={() => {
                  setRelationFilter(filter.key);
                  setPage(1);
                }}
                className={`font-black underline-offset-4 hover:underline ${relationFilter === filter.key ? "text-orange-600 underline" : "text-slate-500"}`}
              >
                {filter.label}
              </button>
            ))}
            <span className="ml-2 rounded-lg bg-slate-100 px-3 py-1 font-black text-slate-900">거래처수 {total.toLocaleString("ko-KR")}개</span>
          </div>
        }
        action={
          <div className="flex flex-wrap gap-2">
            <ActionButton type="button" onClick={openNewCustomer}>F2 새 거래처</ActionButton>
            <ActionButton type="button" variant="secondary" onClick={() => fileInputRef.current?.click()}>엑셀등록</ActionButton>
            <ActionButton type="button" variant="secondary" onClick={() => void downloadCustomers()}>거래처정보 다운로드</ActionButton>
            <button
              type="button"
              onClick={downloadCustomerTemplate}
              className="inline-flex h-11 w-11 items-center justify-center rounded-md border-0 bg-transparent p-0 text-emerald-600 hover:bg-orange-50"
              aria-label="엑셀폼 다운로드"
              title="엑셀폼 다운로드"
            >
              <ExcelFormIcon />
            </button>
            <input ref={fileInputRef} type="file" accept=".xlsx,.xls" className="hidden" onChange={(event) => {
              const file = event.target.files?.[0];
              if (file) void uploadCustomers(file);
              event.target.value = "";
            }} />
          </div>
        }
      >
        <div className="mb-3 flex flex-wrap items-center justify-between gap-2">
          <div className="flex flex-wrap items-center gap-2">
            <ActionButton type="button" variant="secondary" onClick={() => setCustomerBulkOpen(true)}>수정</ActionButton>
            <span className="text-xs font-bold text-slate-500">선택 {selectedCustomerKeys.length.toLocaleString("ko-KR")}개</span>
          </div>
          <input
            className="field-input w-full max-w-sm rounded-md border border-slate-200 px-3 py-2 text-sm"
            value={query}
            onChange={(event) => {
              setPage(1);
              setQuery(event.target.value);
            }}
            placeholder="거래처명 / 코드 검색"
          />
        </div>
        <div className="fn-table-shell overflow-x-auto [&_td:first-child]:pl-4 [&_td:last-child]:pr-4 [&_th:first-child]:pl-4 [&_th:last-child]:pr-4">
          <table className="w-full min-w-[1080px] table-fixed text-sm">
            <thead className="border-b border-gray-200 bg-gray-50 text-xs font-semibold text-gray-500">
              <tr>
                <th className="w-16 py-2 text-center">
                  <input
                    type="checkbox"
                    className="h-5 w-5"
                    checked={customerSelection.allSelected}
                    onChange={(event) => customerSelection.toggleAll(event.target.checked)}
                    aria-label="거래처 전체선택"
                  />
                </th>
                <th className="w-36 py-2 pl-3 text-left">거래처코드</th>
                <th className="w-48 py-2 text-left">거래처명</th>
                <th className="w-24 py-2 text-left">속성</th>
                <th className="w-24 py-2 text-left">파일업로드 폴더</th>
                <th className="w-36 py-2 text-left">사업자번호</th>
                <th className="w-28 py-2 text-left">담당자</th>
                <th className="w-36 py-2 text-left">전화번호</th>
                <th className="w-40 py-2 text-left">메모</th>
              </tr>
            </thead>
            <tbody>
              {customers.map((customer, index) => {
                const key = customerRowKey(customer);
                const selected = selectedCustomerKeys.includes(key);
                return (
                <tr key={customer.id || customer.customer_code} onClick={() => openCustomer(customer)} className={`cursor-pointer border-b border-gray-100 ${selected ? "bg-sky-50" : "hover:bg-orange-50/60"}`}>
                  <td className="py-2 text-center" onClick={(event) => event.stopPropagation()}>
                    <SelectionNumberButton index={index} selected={selected} onMouseDown={(event) => customerSelection.beginSelection(key, index, event)} onMouseEnter={() => customerSelection.continueSelection(key, index)} />
                  </td>
                  <td className="truncate py-2 pl-3 font-black">{customer.customer_code || customer.cust_code || "-"}</td>
                  <td className="truncate py-2 font-bold">{customer.customer_name || customer.cust_name || "-"}</td>
                  <td className="truncate py-2 text-slate-500">{customerAttributeLabel(customer.customer_type || customer.customer_type_label)}</td>
                  <td className="py-2" onClick={(event) => event.stopPropagation()}>
                    <FolderAttachmentButton count={customerFileCounts[key]} title="거래처 첨부파일" onClick={() => setCustomerFile(customer)} />
                  </td>
                  <td className="truncate py-2 text-slate-500">{customer.business_no || "-"}</td>
                  <td className="truncate py-2 text-slate-500">{customer.contact_name || "-"}</td>
                  <td className="truncate py-2 text-slate-500">{customer.phone || "-"}</td>
                  <td className="truncate py-2 text-slate-500" title={customer.memo || ""}>{customer.memo ? `${customer.memo.slice(0, 10)}${customer.memo.length > 10 ? "..." : ""}` : "-"}</td>
                </tr>
              );})}
            </tbody>
          </table>
          {!customers.length && <EmptyState title={loading ? "" : "거래처가 없습니다."} />}
        </div>
        <div className="mt-4 flex items-center justify-center gap-1">
          {pageNumbers.map((number) => (
            <button key={number} type="button" onClick={() => setPage(number)} className={`h-7 min-w-7 rounded px-2 text-xs font-black ${page === number ? "bg-slate-950 text-white" : "border border-slate-200 text-slate-500 hover:bg-slate-50"}`}>{number}</button>
          ))}
        </div>
      </Panel>
      {customerFile && (
        <AccountFileModal
          accountType="customer"
          accountId={customerRowKey(customerFile)}
          title={customerFile.customer_name || customerFile.cust_name || customerFile.customer_code || "거래처"}
          onClose={() => setCustomerFile(null)}
          onChanged={(count) => setCustomerFileCounts((prev) => ({ ...prev, [customerRowKey(customerFile)]: count }))}
        />
      )}
      {customerBulkOpen && (
        <BulkMultiEditModal<CustomerBulkField, FnCustomer>
          title="거래처 선택수정"
          description={`선택 ${selectedCustomers.length.toLocaleString("ko-KR")}개 거래처의 값을 수정합니다.`}
          fields={customerBulkFields}
          selectedFields={customerBulkSelectedFields}
          setSelectedFields={setCustomerBulkSelectedFields}
          fieldPickerOpen={customerBulkFieldPickerOpen}
          setFieldPickerOpen={setCustomerBulkFieldPickerOpen}
          commonField={customerBulkCommonField}
          setCommonField={setCustomerBulkCommonField}
          commonValue={customerBulkCommonValue}
          setCommonValue={setCustomerBulkCommonValue}
          rowDrafts={customerBulkDrafts}
          setRowDrafts={setCustomerBulkDrafts}
          rows={selectedCustomers}
          rowKeys={selectedCustomers.map(customerRowKey)}
          selectedRowKeys={selectedCustomerKeys}
          setSelectedRowKeys={setSelectedCustomerKeys}
          getRowKey={customerRowKey}
          getRowName={(customer) => String(customer.customer_name || customer.cust_name || "-")}
          getRowSubLabel={(customer) => String(customer.customer_code || customer.cust_code || "-")}
          getCurrentValue={(customer, field) => {
            if (field === "customer_type") return normalizeCustomerAttribute(customer.customer_type || customer.customer_type_label);
            return String(customer[field as keyof FnCustomer] || "");
          }}
          onClose={() => setCustomerBulkOpen(false)}
          onSave={() => void saveCustomerBulkEdit()}
        />
      )}
      {modalOpen && (
        <CustomerEditModal
          draft={draft}
          channelDraft={channelDraft}
          channelCredentials={channelCredentials}
          credentialMeta={credentialMeta}
          credentialsRevealed={credentialsRevealed}
          channelLoading={channelLoading}
          onClose={() => setModalOpen(false)}
          onChange={updateDraft}
          onChannelChange={updateChannelDraft}
          onCredentialChange={updateChannelCredential}
          onRevealCredentials={() => void revealChannelCredentials()}
          onSave={() => void saveCustomerDraft()}
          onDelete={() => void deleteCustomerDraft()}
        />
      )}
    </div>
  );
}

function ProductManagementPanel({ setMessage }: { message: string; setMessage: (value: string) => void }) {
  const pageSize = 20;
  const initialProductEndpoint = `/api/fnos/products/master?${new URLSearchParams({ page: "1", pageSize: String(pageSize), relation: "plain" }).toString()}`;
  const initialProductData = readInitialCachedJson<{ products?: FnProduct[]; warehouses?: WarehouseOption[]; total?: number; ok?: boolean; error?: string }>(initialProductEndpoint, { storageTtl: 10 * 60_000 });
  const [products, setProducts] = useState<FnProduct[]>(initialProductData?.products || []);
  const [warehouses, setWarehouses] = useState<WarehouseOption[]>(initialProductData?.warehouses || []);
  const [query, setQuery] = useState("");
  const [searchByCode, setSearchByCode] = useState(false);
  const [page, setPage] = useState(1);
  const [total, setTotal] = useState(Number(initialProductData?.total || 0));
  const [loading, setLoading] = useState(!initialProductData);
  const [modalOpen, setModalOpen] = useState(false);
  const [productMessage, setProductMessage] = useState("");
  const [draft, setDraft] = useState<Record<string, string>>({});
  const [bomRows, setBomRows] = useState<ProductBomRow[]>([]);
  const [importLinks, setImportLinks] = useState<ProductImportLinkRow[]>([]);
  const [relationFilter, setRelationFilter] = useState<ProductRelationFilter>("plain");
  const [selectedProductKeys, setSelectedProductKeys] = useState<string[]>([]);
  const [productSelecting, setProductSelecting] = useState(false);
  const [productBulkOpen, setProductBulkOpen] = useState(false);
  const [productBulkSelectedFields, setProductBulkSelectedFields] = useState<ProductBulkField[]>(["product_name", "cost_price", "standard_price"]);
  const [productBulkFieldPickerOpen, setProductBulkFieldPickerOpen] = useState(false);
  const [productBulkCommonField, setProductBulkCommonField] = useState<ProductBulkField>("product_name");
  const [productBulkCommonValue, setProductBulkCommonValue] = useState("");
  const [productBulkDrafts, setProductBulkDrafts] = useState<Record<string, Partial<Record<ProductBulkField, string>>>>({});
  const fileInputRef = useRef<HTMLInputElement | null>(null);
  const productSelectModeRef = useRef<"select" | "deselect">("select");
  const usableWarehouses = warehouses.filter(isUsableWarehouse).sort(sortWarehousesByCode);
  const pageCount = Math.max(1, Math.ceil(total / pageSize));
  const productKeys = products.map((product) => product.id || product.product_code || product.sku || "").filter(Boolean);
  const selectedProducts = products.filter((product) => selectedProductKeys.includes(product.id || product.product_code || product.sku || ""));
  const productSelection = useCheckboxColumnSelection({ keys: productKeys, selectedKeys: selectedProductKeys, setSelectedKeys: setSelectedProductKeys, enabled: !modalOpen && !productBulkOpen });

  function blankDraft() {
    return {
      id: "",
      product_code: "",
      product_name: "",
      product_attribute: "plain",
      product_kind: "plain",
      cost_price: "",
      standard_price: "",
      ...Object.fromEntries(usableWarehouses.map((warehouse) => [`stock_${warehouse.warehouse_code}`, ""])),
    };
  }

  async function loadProducts(nextPage = page, nextQuery = query, nextFilter = relationFilter, nextSearchByCode = searchByCode) {
    setLoading(true);
    try {
      const params = new URLSearchParams({ page: String(nextPage), pageSize: String(pageSize), relation: nextFilter });
      if (nextQuery.trim()) params.set("q", nextQuery.trim());
      if (nextSearchByCode) params.set("searchField", "code");
      const endpoint = `/api/fnos/products/master?${params.toString()}`;
      const cached = readCachedJson<{ products?: FnProduct[]; warehouses?: WarehouseOption[]; total?: number; ok?: boolean; error?: string }>(endpoint, { storageTtl: 10 * 60_000 });
      if (cached) {
        setProducts(sortRowsByManagementName(cached.products || [], (product) => product.product_name, (product) => product.product_code || product.sku));
        setWarehouses(sortRowsByManagementName(cached.warehouses || [], (warehouse) => warehouse.warehouse_name, (warehouse) => warehouse.warehouse_code));
        setTotal(Number(cached.total || 0));
        setLoading(false);
      }
      const data = await cachedClientJson<{ products?: FnProduct[]; warehouses?: WarehouseOption[]; total?: number; ok?: boolean; error?: string }>(endpoint, { ttl: 5 * 60_000, storageTtl: 10 * 60_000 });
      if (data.ok === false) {
        setProductMessage(data.error || "품목 조회 실패");
        return;
      }
      setProducts(sortRowsByManagementName(data.products || [], (product) => product.product_name, (product) => product.product_code || product.sku));
      setWarehouses(sortRowsByManagementName(data.warehouses || [], (warehouse) => warehouse.warehouse_name, (warehouse) => warehouse.warehouse_code));
      setTotal(Number(data.total || 0));
    } finally {
      setLoading(false);
    }
  }

  useEffect(() => {
    const timer = window.setTimeout(() => {
      void loadProducts(page, query, relationFilter, searchByCode);
    }, 0);
    return () => window.clearTimeout(timer);
  }, [page, query, relationFilter, searchByCode]);

  useEffect(() => {
    setSelectedProductKeys([]);
  }, [page, query, relationFilter, searchByCode]);

  useEffect(() => {
    function stopSelecting() {
      setProductSelecting(false);
    }
    window.addEventListener("mouseup", stopSelecting);
    return () => window.removeEventListener("mouseup", stopSelecting);
  }, []);

  useEffect(() => {
    const onKeyDown = (event: globalThis.KeyboardEvent) => {
      if (event.key !== "F2") return;
      event.preventDefault();
      openNewProduct();
    };
    window.addEventListener("keydown", onKeyDown);
    return () => window.removeEventListener("keydown", onKeyDown);
  }, [warehouses]);

  function openNewProduct() {
    setDraft(blankDraft());
    setBomRows([]);
    setImportLinks([]);
    setModalOpen(true);
  }

  function openProduct(product: FnProduct) {
    const stockValues = Object.fromEntries(usableWarehouses.map((warehouse) => {
      const stock = (product.inventory || []).find((item) => item.warehouse_code === warehouse.warehouse_code);
      return [`stock_${warehouse.warehouse_code}`, stock?.qty != null ? String(stock.qty) : ""];
    }));
    setDraft({
      id: product.id || "",
      product_code: product.product_code || product.sku || "",
      product_name: product.product_name || "",
      product_attribute: productAttributeOf(product),
      product_kind: productAttributeOf(product),
      cost_price: product.cost_price != null ? String(product.cost_price) : "",
      standard_price: product.standard_price != null ? String(product.standard_price) : "",
      ...stockValues,
    });
    setBomRows(product.bom || []);
    setImportLinks(product.import_links || []);
    setModalOpen(true);
  }

  function updateDraft(key: string, value: string) {
    setDraft((prev) => ({ ...prev, [key]: value }));
  }

  function productRowKey(product: FnProduct) {
    return product.id || product.product_code || product.sku || "";
  }

  function productChannelStock(product: FnProduct, target: "fn" | "coupang" | "naver") {
    return (product.inventory || []).reduce((sum, stock) => {
      const code = String(stock.warehouse_code || "").trim();
      const name = String(stock.warehouse_name || "").trim().toLowerCase();
      const isMatch =
        target === "fn"
          ? code === "100" || name.includes("에프엔") || name.includes("본사") || name === "fn"
          : target === "coupang"
            ? code === "101" || name.includes("쿠팡") || name.includes("로켓")
            : code === "102" || name.includes("네이버") || name.includes("n배송");
      return isMatch ? sum + Number(stock.qty || 0) : sum;
    }, 0);
  }

  function productChannelStockText(product: FnProduct) {
    return (["fn", "coupang", "naver"] as const)
      .map((target) => {
        const qty = productChannelStock(product, target);
        return qty === 0 ? "-" : qty.toLocaleString("ko-KR");
      })
      .join(" ｜ ");
  }

  function setProductSelected(key: string, selected: boolean) {
    if (!key) return;
    setSelectedProductKeys((prev) => selected ? Array.from(new Set([...prev, key])) : prev.filter((item) => item !== key));
  }

  function toggleProductSelected(key: string) {
    if (!key) return;
    setSelectedProductKeys((prev) => prev.includes(key) ? prev.filter((item) => item !== key) : [...prev, key]);
  }

  async function saveProductDraft() {
    const productCode = String(draft.product_code || "").trim();
    const rawProductName = String(draft.product_name || "").trim();
    const productAttribute = normalizeProductAttribute(draft.product_attribute ?? draft.product_kind);
    const productName = productNameWithAttribute(rawProductName, productAttribute);
    if (!productCode || !rawProductName) {
      window.alert("품목코드와 품목명은 필수입니다.");
      return;
    }
    const inventory = usableWarehouses
      .map((warehouse) => ({
        warehouse_id: warehouse.id,
        warehouse_code: warehouse.warehouse_code,
        qty: draft[`stock_${warehouse.warehouse_code}`],
      }))
      .filter((item) => String(item.qty ?? "").trim() !== "");
    const res = await fetch("/api/fnos/products/master", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      credentials: "include",
      body: JSON.stringify({
        product: {
          id: draft.id,
          product_code: productCode,
          product_name: productName,
          product_attribute: productAttribute,
          product_kind: productAttribute,
          cost_price: draft.cost_price,
          standard_price: draft.standard_price,
        },
        inventory,
        bom: bomRows,
      }),
    });
    const data = await res.json().catch(() => ({}));
    if (!res.ok || data.ok === false) {
      window.alert(data.error || "품목 저장 실패");
      return;
    }
    setProductMessage(`품목 저장 완료: ${productCode}`);
    setMessage("");
    setModalOpen(false);
    invalidateClientCache("/api/fnos/products/master");
    await loadProducts(page, query);
  }

  async function deleteProductDraft() {
    const productId = String(draft.id || "").trim();
    const productCode = String(draft.product_code || "").trim();
    if (!productId && !productCode) return;
    if (!window.confirm("이 품목을 삭제할까요?")) return;
    const res = await fetch("/api/fnos/products/master", {
      method: "DELETE",
      headers: { "Content-Type": "application/json" },
      credentials: "include",
      body: JSON.stringify({ id: productId, product_code: productCode }),
    });
    const data = await res.json().catch(() => ({}));
    if (!res.ok || data.ok === false) {
      setProductMessage(data.error || "품목 삭제 실패");
      return;
    }
    setProductMessage(`품목 삭제 완료: ${productCode}`);
    setModalOpen(false);
    invalidateClientCache("/api/fnos/products/master");
    await loadProducts(page, query, relationFilter, searchByCode);
  }

  async function saveProductBulkEdit() {
    if (!selectedProducts.length) {
      setProductMessage("수정할 품목을 먼저 선택해 주세요.");
      return;
    }
    let saved = 0;
    for (const product of selectedProducts) {
      const key = productRowKey(product);
      const draftValues = productBulkDrafts[key] || {};
      const productAttribute = productBulkSelectedFields.includes("product_attribute") ? normalizeProductAttribute(draftValues.product_attribute ?? productAttributeOf(product)) : productAttributeOf(product);
      const rawProductName = productBulkSelectedFields.includes("product_name") ? draftValues.product_name ?? String(product.product_name || "") : String(product.product_name || "");
      const productName = productNameWithAttribute(rawProductName, productAttribute);
      const res = await fetch("/api/fnos/products/master", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        credentials: "include",
        body: JSON.stringify({
          product: {
            id: product.id,
            product_code: product.product_code || product.sku || "",
            product_name: productName,
            product_attribute: productAttribute,
            product_kind: productAttribute,
            cost_price: productBulkSelectedFields.includes("cost_price") ? draftValues.cost_price ?? product.cost_price : product.cost_price,
            standard_price: productBulkSelectedFields.includes("standard_price") ? draftValues.standard_price ?? product.standard_price : product.standard_price,
          },
        }),
      });
      if (res.ok) saved += 1;
    }
    setProductMessage(`선택수정 완료: ${saved.toLocaleString("ko-KR")}건`);
    setProductBulkOpen(false);
    setProductBulkDrafts({});
    setProductBulkCommonValue("");
    setSelectedProductKeys([]);
    invalidateClientCache("/api/fnos/products/master");
    invalidateClientCache("/api/fnos/products/search");
    await loadProducts(page, query, relationFilter, searchByCode);
  }

  function downloadProductTemplate() {
    void downloadTableXlsx(
      "FN_OS_품목_엑셀폼.xlsx",
      "품목",
      ["품목코드", "품목명", "속성", "입고가", "출고가", "창고코드", "재고등록(수정)", "BOM구성품코드", "BOM수량"],
      [["SET001", "[SET]세트상품명", "SET", "1200", "5900", warehouses[0]?.warehouse_code || "100", "0", "FL0001", "2"]],
    );
  }

  async function downloadVisibleProducts() {
    const filterLabel = relationFilters.find((filter) => filter.key === relationFilter)?.label || "품목";
    const params = new URLSearchParams({ page: "1", pageSize: "5000", relation: relationFilter });
    if (query.trim()) params.set("q", query.trim());
    if (searchByCode) params.set("searchField", "code");
    const data = await cachedClientJson<{ products?: FnProduct[]; ok?: boolean; error?: string }>(`/api/fnos/products/master?${params.toString()}`, { ttl: 60_000, storageTtl: 5 * 60_000 }).catch((error) => ({ ok: false, error: error instanceof Error ? error.message : "상품정보 다운로드 대상 조회 실패", products: [] }));
    if (data.ok === false) {
      setProductMessage(data.error || "상품정보 다운로드 대상 조회 실패");
      return;
    }
    const exportProducts = (data.products || []) as FnProduct[];
    const rows = exportProducts.map((product) => [
      product.product_code || product.sku || "",
      product.product_name || "",
      product.product_attribute_label || productAttributeLabel(productAttributeOf(product)),
      String(product.cost_price ?? ""),
      String(product.standard_price ?? ""),
      String(product.current_stock ?? 0),
      (product.inventory || []).map((stock) => `${stock.warehouse_name || stock.warehouse_code}:${Number(stock.qty || 0).toLocaleString("ko-KR")}`).join(" / "),
      (product.bom || []).map((item) => `${item.component_product_code || item.component_sku}:${item.qty_per_unit}`).join(" / "),
      (product.import_links || []).map((item) => `${item.import_product_name || item.import_product_id}${item.import_option_name ? `/${item.import_option_name}` : ""}`).join(" / "),
    ]);
    void downloadTableXlsx(
      `FN_OS_품목_${filterLabel}_${exportProducts.length}건_${todayMmdd()}.xlsx`,
      "품목정보",
      ["품목코드", "품목명", "속성", "입고가", "출고가", "현재고", "창고별재고", "BOM구성", "수입연동"],
      rows,
    );
  }

  async function uploadProducts(file: File) {
    const rows = await readXlsxObjects(file);
    const allData = await cachedClientJson<{ products?: FnProduct[] }>("/api/fnos/products/master?page=1&pageSize=5000", { ttl: 60_000, storageTtl: 5 * 60_000 });
    const existing = new Map<string, FnProduct>((allData.products || []).map((product: FnProduct) => [String(product.product_code || product.sku || ""), product]));
    const normalized = rows
      .map((row) => {
        const rawProductName = String(row["품목명"] || row["상품명"] || "").trim();
        const rawAttribute = String(row["속성"] || row["품목속성"] || "").toUpperCase();
        const productAttribute = rawAttribute ? normalizeProductAttribute(rawAttribute, "plain") : "plain";
        return {
          product_code: String(row["품목코드"] || row["SKU"] || row["sku"] || "").trim(),
          product_name: productNameWithAttribute(rawProductName, productAttribute),
          product_attribute: productAttribute,
          cost_price: String(row["입고가"] || row["매입가"] || "").trim(),
          standard_price: String(row["출고가"] || row["판매가"] || "").trim(),
          warehouse_code: String(row["창고코드"] || warehouses[0]?.warehouse_code || "100").trim(),
          qty: String(row["재고등록(수정)"] || row["재고"] || "").trim(),
          bom_component_code: String(row["BOM구성품코드"] || row["BOM연동품목코드"] || row["BOM품목코드"] || row["bom_component_code"] || "").trim(),
          bom_qty: String(row["BOM수량"] || row["BOM연동수량"] || row["bom_qty"] || "").trim(),
        };
      })
      .filter((row) => row.product_code && row.product_name);
    const grouped = Array.from(normalized.reduce((map, row) => {
      const current = map.get(row.product_code) || { ...row, bom: [] as Array<{ component_code: string; qty: string }> };
      if (row.bom_component_code) current.bom.push({ component_code: row.bom_component_code, qty: row.bom_qty || "1" });
      map.set(row.product_code, current);
      return map;
    }, new Map<string, typeof normalized[number] & { bom: Array<{ component_code: string; qty: string }> }>()).values());
    const exactMatches = grouped.filter((row) => {
      const found = existing.get(row.product_code);
      return found && String(found.product_name || "").trim() === row.product_name;
    });
    const overwrite = exactMatches.length
      ? window.confirm(`${exactMatches.length}개 품목의 품목코드와 품목명이 일치합니다. 현재 엑셀 데이터로 덮어쓰기 하시겠습니까?\n\n확인: 덮어쓰기\n취소: 기존 항목 스킵`)
      : false;
    let saved = 0;
    let skipped = 0;
    const processedRows: typeof grouped = [];
    for (const row of grouped) {
      const found = existing.get(row.product_code);
      if (found && !overwrite) {
        skipped += 1;
        continue;
      }
      if (found && String(found.product_name || "").trim() !== row.product_name) {
        skipped += 1;
        continue;
      }
      const res = await fetch("/api/fnos/products/master", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        credentials: "include",
        body: JSON.stringify({
          product: {
            id: found?.id,
            product_code: row.product_code,
            product_name: row.product_name,
            product_attribute: row.product_attribute,
            product_kind: row.product_attribute,
            cost_price: row.cost_price,
            standard_price: row.standard_price,
          },
          inventory: row.qty === "" ? [] : [{ warehouse_code: row.warehouse_code, qty: row.qty }],
        }),
      });
      if (res.ok) {
        saved += 1;
        processedRows.push(row);
      }
    }
    invalidateClientCache("/api/fnos/products/master");
    const refreshedData = await cachedClientJson<{ products?: FnProduct[] }>("/api/fnos/products/master?page=1&pageSize=5000", { ttl: 0, storageTtl: 0, force: true });
    const productsByCode = new Map<string, FnProduct>((refreshedData.products || []).map((product: FnProduct) => [String(product.product_code || product.sku || ""), product]));
    for (const row of processedRows.filter((item) => item.bom.length > 0)) {
      const parent = productsByCode.get(row.product_code);
      if (!parent) continue;
      const bom = row.bom
        .map((item) => {
          const component = productsByCode.get(item.component_code);
          return component ? {
            component_product_id: component.id,
            component_sku: component.product_code || component.sku,
            component_product_code: component.product_code || component.sku,
            component_product_name: component.product_name,
            qty_per_unit: Number(String(item.qty || "1").replace(/[^\d.-]/g, "")) || 1,
          } : null;
        })
        .filter(Boolean);
      if (!bom.length) continue;
      await fetch("/api/fnos/products/master", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        credentials: "include",
        body: JSON.stringify({
          product: {
            id: parent.id,
            product_code: row.product_code,
            product_name: row.product_name,
            product_attribute: row.product_attribute,
            product_kind: row.product_attribute,
            cost_price: row.cost_price,
            standard_price: row.standard_price,
          },
          inventory: [],
          bom,
        }),
      });
    }
    setProductMessage(`엑셀 등록 완료: 저장 ${saved}건 / 스킵 ${skipped}건`);
    setMessage("");
    invalidateClientCache("/api/fnos/products/master");
    await loadProducts(1, query);
    setPage(1);
  }

  const pageNumbers = Array.from({ length: Math.min(6, pageCount) }, (_, index) => {
    const start = Math.min(Math.max(1, page - 2), Math.max(1, pageCount - 5));
    return start + index;
  }).filter((value) => value <= pageCount);
  const relationFilters: Array<{ key: ProductRelationFilter; label: string }> = [
    { key: "plain", label: "일반" },
    { key: "set", label: "SET" },
    { key: "rg", label: "RG" },
    { key: "import", label: "수입연동" },
    { key: "all", label: "전체품목" },
  ];

  return (
    <div className="space-y-4">
      <Panel
        title="품목관리"
        subtitle={
          <div className="flex flex-wrap items-center gap-2 text-sm">
            {relationFilters.map((filter) => (
              <button
                key={filter.key}
                type="button"
                onClick={() => {
                  setRelationFilter(filter.key);
                  setPage(1);
                }}
                className={`font-black underline-offset-4 hover:underline ${
                  relationFilter === filter.key ? "text-orange-600 underline" : "text-slate-500"
                }`}
              >
                {filter.label}
              </button>
            ))}
            <span className="ml-2 rounded-lg bg-slate-100 px-3 py-1 font-black text-slate-900">상품수 {total.toLocaleString("ko-KR")}개</span>
          </div>
        }
        action={
          <div className="flex flex-wrap gap-2">
            <ActionButton type="button" onClick={openNewProduct}>F2 새 품목</ActionButton>
            <ActionButton type="button" variant="secondary" onClick={() => fileInputRef.current?.click()}>엑셀등록</ActionButton>
            <ActionButton type="button" variant="secondary" onClick={downloadVisibleProducts}>상품정보 다운로드</ActionButton>
            <button
              type="button"
              onClick={downloadProductTemplate}
              className="inline-flex h-11 w-11 items-center justify-center rounded-md border-0 bg-transparent p-0 text-emerald-600 hover:bg-orange-50"
              aria-label="엑셀폼 다운로드"
              title="엑셀폼 다운로드"
            >
              <ExcelFormIcon />
            </button>
            <input ref={fileInputRef} type="file" accept=".xlsx,.xls" className="hidden" onChange={(event) => {
              const file = event.target.files?.[0];
              if (file) void uploadProducts(file);
              event.target.value = "";
            }} />
          </div>
        }
      >
        <div className="mb-3 flex flex-wrap items-center justify-between gap-2">
          <div className="flex flex-wrap items-center gap-2">
            <ActionButton type="button" variant="secondary" onClick={() => setProductBulkOpen(true)}>수정</ActionButton>
            <span className="text-xs font-bold text-slate-500">선택 {selectedProductKeys.length.toLocaleString("ko-KR")}개</span>
          </div>
          <input
            className="field-input w-full max-w-sm rounded-md border border-slate-200 px-3 py-2 text-sm"
            value={query}
            onChange={(event) => {
              setPage(1);
              setSearchByCode(false);
              setQuery(event.target.value);
            }}
            placeholder="품목명 검색"
          />
        </div>
        <div className="fn-table-shell overflow-x-auto [&_td:first-child]:pl-4 [&_td:last-child]:pr-4 [&_th:first-child]:pl-4 [&_th:last-child]:pr-4">
          <table className="w-full min-w-[1040px] table-fixed text-sm">
            <thead className="border-b border-gray-200 bg-gray-50 text-xs font-semibold text-gray-500">
              <tr>
                <th className="w-16 py-2 text-center">
                  <input
                    type="checkbox"
                    className="h-5 w-5"
                    checked={productSelection.allSelected}
                    onChange={(event) => productSelection.toggleAll(event.target.checked)}
                    aria-label="품목 전체선택"
                  />
                </th>
                <th className="w-32 py-2 pl-3 text-left">품목코드</th>
                <th className="w-72 py-2 text-left">품목명</th>
                <th className="w-24 py-2 text-right">입고가</th>
                <th className="w-24 py-2 text-right">출고가</th>
                <th className="w-60 py-2 text-center">재고 현황(FN ｜ C ｜ N)</th>
                <th className="w-32 py-2 text-left">BOM / 수입연동</th>
              </tr>
            </thead>
            <tbody>
              {products.map((product, index) => {
                const key = productRowKey(product);
                const selected = selectedProductKeys.includes(key);
                return (
                <tr key={product.id || product.product_code} onClick={() => openProduct(product)} className={`cursor-pointer border-b border-gray-100 ${selected ? "bg-sky-50" : "hover:bg-orange-50/60"}`}>
                  <td className="py-2 text-center" onClick={(event) => event.stopPropagation()}>
                    <SelectionNumberButton index={index} selected={selected} onMouseDown={(event) => productSelection.beginSelection(key, index, event)} onMouseEnter={() => productSelection.continueSelection(key, index)} />
                  </td>
                  <td className="truncate py-2 pl-3 font-black">{product.product_code || product.sku || "-"}</td>
                  <td className="truncate py-2 font-bold" title={product.product_name || ""}>{product.product_name || "-"}</td>
                  <td className="py-2 text-right">{krw(Number(product.cost_price || 0))}</td>
                  <td className="py-2 text-right">{krw(Number(product.standard_price || 0))}</td>
                  <td className="whitespace-nowrap py-2 text-center font-normal tabular-nums text-slate-700">{productChannelStockText(product)}</td>
                  <td className="py-2 text-xs font-black">
                    <StatusBadge tone={(product.bom || []).length ? "success" : "muted"} className="mr-2">BOM {(product.bom || []).length}</StatusBadge>
                    <StatusBadge tone={(product.import_links || []).length ? "orange" : "muted"}>수입 {(product.import_links || []).length}</StatusBadge>
                  </td>
                </tr>
              );})}
            </tbody>
          </table>
          {!products.length && <EmptyState title={loading ? "" : "품목이 없습니다."} />}
        </div>
        <div className="mt-4 flex items-center justify-center gap-1">
          {pageNumbers.map((number) => (
            <button
              key={number}
              type="button"
              onClick={() => setPage(number)}
              className={`h-7 min-w-7 rounded px-2 text-xs font-black ${page === number ? "bg-slate-950 text-white" : "border border-slate-200 text-slate-500 hover:bg-slate-50"}`}
            >
              {number}
            </button>
          ))}
        </div>
      </Panel>

      {productBulkOpen && (
        <BulkMultiEditModal<ProductBulkField, FnProduct>
          title="품목 선택수정"
          description={`선택 ${selectedProducts.length.toLocaleString("ko-KR")}개 품목의 값을 수정합니다.`}
          fields={productBulkFields}
          selectedFields={productBulkSelectedFields}
          setSelectedFields={setProductBulkSelectedFields}
          fieldPickerOpen={productBulkFieldPickerOpen}
          setFieldPickerOpen={setProductBulkFieldPickerOpen}
          commonField={productBulkCommonField}
          setCommonField={setProductBulkCommonField}
          commonValue={productBulkCommonValue}
          setCommonValue={setProductBulkCommonValue}
          rowDrafts={productBulkDrafts}
          setRowDrafts={setProductBulkDrafts}
          rows={selectedProducts}
          rowKeys={selectedProducts.map(productRowKey)}
          selectedRowKeys={selectedProductKeys}
          setSelectedRowKeys={setSelectedProductKeys}
          getRowKey={productRowKey}
          getRowName={(product) => String(product.product_name || "-")}
          getRowSubLabel={(product) => String(product.product_code || product.sku || "-")}
          getCurrentValue={(product, field) => {
            if (field === "product_attribute") return productAttributeOf(product);
            if (field === "product_name") return String(product.product_name || "");
            return String(product[field as keyof FnProduct] ?? "");
          }}
          onClose={() => setProductBulkOpen(false)}
          onSave={() => void saveProductBulkEdit()}
        />
      )}

      {modalOpen && (
        <ProductEditModal
          draft={draft}
          warehouses={usableWarehouses}
          bomRows={bomRows}
          importLinks={importLinks}
          onClose={() => setModalOpen(false)}
          onChange={updateDraft}
          onBomRowsChange={setBomRows}
          onSave={() => void saveProductDraft()}
          onDelete={() => void deleteProductDraft()}
        />
      )}
    </div>
  );
}

function WarehouseManagementPanel({ message, setMessage }: { message: string; setMessage: (value: string) => void }) {
  const [warehouses, setWarehouses] = useState<FnWarehouse[]>([]);
  const [query, setQuery] = useState("");
  const [total, setTotal] = useState(0);
  const [loading, setLoading] = useState(false);
  const [modalOpen, setModalOpen] = useState(false);
  const [draft, setDraft] = useState<Record<string, string>>({});
  const [selectedWarehouseKeys, setSelectedWarehouseKeys] = useState<string[]>([]);
  const [warehouseSelecting, setWarehouseSelecting] = useState(false);
  const [warehouseBulkOpen, setWarehouseBulkOpen] = useState(false);
  const [warehouseBulkSelectedFields, setWarehouseBulkSelectedFields] = useState<WarehouseBulkField[]>(["warehouse_type"]);
  const [warehouseBulkFieldPickerOpen, setWarehouseBulkFieldPickerOpen] = useState(false);
  const [warehouseBulkCommonField, setWarehouseBulkCommonField] = useState<WarehouseBulkField>("warehouse_type");
  const [warehouseBulkCommonValue, setWarehouseBulkCommonValue] = useState("");
  const [warehouseBulkDrafts, setWarehouseBulkDrafts] = useState<Record<string, Partial<Record<WarehouseBulkField, string>>>>({});
  const fileInputRef = useRef<HTMLInputElement | null>(null);
  const warehouseSelectModeRef = useRef<"select" | "deselect">("select");
  const warehouseKeys = warehouses.map((warehouse) => warehouseRowKey(warehouse)).filter(Boolean);
  const selectedWarehouses = warehouses.filter((warehouse) => selectedWarehouseKeys.includes(warehouseRowKey(warehouse)));
  const warehouseSelection = useCheckboxColumnSelection({ keys: warehouseKeys, selectedKeys: selectedWarehouseKeys, setSelectedKeys: setSelectedWarehouseKeys, enabled: !modalOpen && !warehouseBulkOpen });

  function blankWarehouseDraft() {
    return {
      id: "",
      warehouse_type: "general",
      warehouse_code: "",
      warehouse_name: "",
      warehouse_address: "",
      warehouse_phone: "",
      manager_name: "",
      manager_phone: "",
      manager_memo: "",
      memo: "",
    };
  }

  function parseWarehouseMemo(memo?: string) {
    const next = blankWarehouseDraft();
    String(memo || "").split(/\r?\n/).forEach((line) => {
      const [rawKey, ...rest] = line.split(":");
      const key = rawKey.trim();
      const value = rest.join(":").trim();
      if (!key || !value) return;
      if (key === "창고 주소") next.warehouse_address = value;
      else if (key === "창고 연락처") next.warehouse_phone = value;
      else if (key === "담당자 이름") next.manager_name = value;
      else if (key === "담당자 연락처") next.manager_phone = value;
      else if (key === "담당자 메모") next.manager_memo = value;
    });
    const plainMemo = String(memo || "")
      .split(/\r?\n/)
      .filter((line) => !/^(창고 주소|창고 연락처|담당자 이름|담당자 연락처|담당자 메모)\s*:/.test(line.trim()))
      .join("\n")
      .trim();
    next.memo = plainMemo;
    return next;
  }

  function composeWarehouseMemo(source: Record<string, string>) {
    return [
      source.memo,
      source.warehouse_address ? `창고 주소: ${source.warehouse_address}` : "",
      source.warehouse_phone ? `창고 연락처: ${source.warehouse_phone}` : "",
      source.manager_name ? `담당자 이름: ${source.manager_name}` : "",
      source.manager_phone ? `담당자 연락처: ${source.manager_phone}` : "",
      source.manager_memo ? `담당자 메모: ${source.manager_memo}` : "",
    ].filter(Boolean).join("\n");
  }

  async function loadWarehouses(nextQuery = query) {
    setLoading(true);
    try {
      const params = new URLSearchParams({ page: "1", pageSize: "5000" });
      if (nextQuery.trim()) params.set("q", nextQuery.trim());
      const endpoint = `/api/fnos/warehouses?${params.toString()}`;
      const cached = readCachedJson<{ warehouses?: FnWarehouse[]; total?: number; ok?: boolean; error?: string }>(endpoint, { storageTtl: 10 * 60_000 });
      if (cached) {
        setWarehouses(sortRowsByManagementName(cached.warehouses || [], (warehouse) => warehouse.warehouse_name, (warehouse) => warehouse.warehouse_code));
        setTotal(Number(cached.total || 0));
        setLoading(false);
      }
      const data = await cachedClientJson<{ warehouses?: FnWarehouse[]; total?: number; ok?: boolean; error?: string }>(endpoint, { ttl: 5 * 60_000, storageTtl: 10 * 60_000 });
      if (data.ok === false) {
        setMessage(data.error || "창고 조회 실패");
        return;
      }
      setWarehouses(sortRowsByManagementName(data.warehouses || [], (warehouse) => warehouse.warehouse_name, (warehouse) => warehouse.warehouse_code));
      setTotal(Number(data.total || 0));
    } finally {
      setLoading(false);
    }
  }

  useEffect(() => {
    const timer = window.setTimeout(() => void loadWarehouses(query), 0);
    return () => window.clearTimeout(timer);
  }, [query]);

  useEffect(() => {
    setSelectedWarehouseKeys([]);
  }, [query]);

  useEffect(() => {
    function stopSelecting() {
      setWarehouseSelecting(false);
    }
    window.addEventListener("mouseup", stopSelecting);
    return () => window.removeEventListener("mouseup", stopSelecting);
  }, []);

  useEffect(() => {
    const onKeyDown = (event: globalThis.KeyboardEvent) => {
      if (event.key !== "F2") return;
      event.preventDefault();
      openNewWarehouse();
    };
    window.addEventListener("keydown", onKeyDown);
    return () => window.removeEventListener("keydown", onKeyDown);
  }, []);

  function openNewWarehouse() {
    setDraft(blankWarehouseDraft());
    setModalOpen(true);
  }

  function openWarehouse(warehouse: FnWarehouse) {
    const memoDraft = parseWarehouseMemo(warehouse.memo);
    setDraft({
      ...memoDraft,
      id: warehouse.id || "",
      warehouse_type: warehouse.warehouse_type || "general",
      warehouse_code: warehouse.warehouse_code || "",
      warehouse_name: warehouse.warehouse_name || "",
    });
    setModalOpen(true);
  }

  function updateDraft(key: string, value: string) {
    setDraft((prev) => ({ ...prev, [key]: value }));
  }

  function warehouseRowKey(warehouse: FnWarehouse) {
    return warehouse.id || warehouse.warehouse_code || "";
  }

  function setWarehouseSelected(key: string, selected: boolean) {
    if (!key) return;
    setSelectedWarehouseKeys((prev) => selected ? Array.from(new Set([...prev, key])) : prev.filter((item) => item !== key));
  }

  async function saveWarehouseDraft() {
    const warehouseType = draft.warehouse_type || "general";
    const warehouseCode = String(draft.warehouse_code || "").trim();
    const warehouseName = String(draft.warehouse_name || "").trim();
    if (!warehouseType || !warehouseCode || !warehouseName) {
      window.alert("속성, 창고코드, 창고명은 필수입니다.");
      return;
    }
    const res = await fetch("/api/fnos/warehouses", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      credentials: "include",
      body: JSON.stringify({
        warehouse: {
          id: draft.id,
          warehouse_type: warehouseType,
          warehouse_code: warehouseCode,
          warehouse_name: warehouseName,
          memo: composeWarehouseMemo(draft),
        },
      }),
    });
    const data = await res.json().catch(() => ({}));
    if (!res.ok || data.ok === false) {
      window.alert(data.error || "창고 저장 실패");
      return;
    }
    invalidateClientCache("/api/fnos/warehouses");
    invalidateClientCache("/api/fnos/products/master");
    setMessage(`창고 저장 완료: ${warehouseCode}`);
    setModalOpen(false);
    await loadWarehouses(query);
  }

  async function deleteWarehouseDraft() {
    if (!draft.id && !draft.warehouse_code) return;
    if (!window.confirm("이 창고를 삭제하시겠습니까?")) return;
    const res = await fetch("/api/fnos/warehouses", {
      method: "DELETE",
      headers: { "Content-Type": "application/json" },
      credentials: "include",
      body: JSON.stringify({ id: draft.id, warehouse_code: draft.warehouse_code }),
    });
    const data = await res.json().catch(() => ({}));
    if (!res.ok || data.ok === false) {
      setMessage(data.error || "창고 삭제 실패");
      return;
    }
    invalidateClientCache("/api/fnos/warehouses");
    invalidateClientCache("/api/fnos/products/master");
    setMessage(`창고 삭제 완료: ${draft.warehouse_code}`);
    setModalOpen(false);
    await loadWarehouses(query);
  }

  async function saveWarehouseBulkEdit() {
    if (!selectedWarehouses.length) {
      setMessage("수정할 창고를 먼저 선택해 주세요.");
      return;
    }
    let saved = 0;
    for (const warehouse of selectedWarehouses) {
      const memoDraft = parseWarehouseMemo(warehouse.memo);
      const key = warehouseRowKey(warehouse);
      const draftValues = warehouseBulkDrafts[key] || {};
      const updates = Object.fromEntries(warehouseBulkSelectedFields.map((field) => [
        field,
        field === "warehouse_type" ? normalizeWarehouseAttribute(draftValues[field] ?? warehouse.warehouse_type ?? "general") : draftValues[field] ?? (field === "warehouse_name" ? warehouse.warehouse_name || "" : memoDraft[field] || ""),
      ]));
      const nextDraft = {
        ...memoDraft,
        id: warehouse.id || "",
        warehouse_type: warehouse.warehouse_type || "general",
        warehouse_code: warehouse.warehouse_code || "",
        warehouse_name: warehouse.warehouse_name || "",
        ...updates,
      };
      const res = await fetch("/api/fnos/warehouses", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        credentials: "include",
        body: JSON.stringify({
          warehouse: {
            id: nextDraft.id,
            warehouse_type: nextDraft.warehouse_type,
            warehouse_code: nextDraft.warehouse_code,
            warehouse_name: nextDraft.warehouse_name,
            memo: composeWarehouseMemo(nextDraft),
          },
        }),
      });
      if (res.ok) saved += 1;
    }
    invalidateClientCache("/api/fnos/warehouses");
    invalidateClientCache("/api/fnos/products/master");
    setMessage(`선택수정 완료: ${saved.toLocaleString("ko-KR")}건`);
    setWarehouseBulkOpen(false);
    setWarehouseBulkDrafts({});
    setWarehouseBulkCommonValue("");
    setSelectedWarehouseKeys([]);
    await loadWarehouses(query);
  }

  function downloadWarehouseTemplate() {
    void downloadTableXlsx(
      "FN_OS_창고_엑셀폼.xlsx",
      "창고",
      ["속성", "창고코드", "창고명", "창고 주소", "창고 연락처", "담당자 이름", "담당자 연락처", "메모"],
      [["일반", "100", "에프엔 본사창고", "서울", "010-0000-0000", "", "", ""]],
    );
  }

  async function uploadWarehouses(file: File) {
    const rows = await readXlsxObjects(file);
    const allData = await cachedClientJson<{ warehouses?: FnWarehouse[] }>("/api/fnos/warehouses?page=1&pageSize=5000", { ttl: 60_000, storageTtl: 5 * 60_000 });
    const existing = new Map<string, FnWarehouse>((allData.warehouses || []).map((warehouse) => [String(warehouse.warehouse_code || ""), warehouse]));
    const normalized = rows
      .map((row) => ({
        warehouse_type: normalizeWarehouseAttribute(row["속성"] || row["창고속성"] || row["구분"] || row["warehouse_type"]),
        warehouse_code: String(row["창고코드"] || row["창고 코드"] || row["코드"] || row["warehouse_code"] || "").trim(),
        warehouse_name: String(row["창고명"] || row["창고명칭"] || row["warehouse_name"] || "").trim(),
        warehouse_address: String(row["창고 주소"] || row["창고주소"] || row["주소"] || "").trim(),
        warehouse_phone: String(row["창고 연락처"] || row["창고연락처"] || row["연락처"] || "").trim(),
        manager_name: String(row["담당자 이름"] || row["담당자이름"] || row["담당자"] || "").trim(),
        manager_phone: String(row["담당자 연락처"] || row["담당자연락처"] || "").trim(),
        memo: String(row["메모"] || row["비고"] || row["적요"] || "").trim(),
      }))
      .filter((row) => row.warehouse_code && row.warehouse_name);
    const exactMatches = normalized.filter((row) => {
      const found = existing.get(row.warehouse_code);
      return found && String(found.warehouse_name || "").trim() === row.warehouse_name;
    });
    const overwrite = exactMatches.length
      ? window.confirm(`${exactMatches.length}개 창고의 창고코드와 창고명이 일치합니다. 현재 엑셀 데이터로 덮어쓰기 하시겠습니까?\n\n확인: 덮어쓰기\n취소: 기존 항목 스킵`)
      : false;
    let saved = 0;
    let skipped = 0;
    for (const row of normalized) {
      const found = existing.get(row.warehouse_code);
      if (found && !overwrite) {
        skipped += 1;
        continue;
      }
      if (found && String(found.warehouse_name || "").trim() !== row.warehouse_name) {
        skipped += 1;
        continue;
      }
      const res = await fetch("/api/fnos/warehouses", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        credentials: "include",
        body: JSON.stringify({
          warehouse: {
            id: found?.id,
            warehouse_type: row.warehouse_type,
            warehouse_code: row.warehouse_code,
            warehouse_name: row.warehouse_name,
            memo: composeWarehouseMemo(row),
          },
        }),
      });
      if (res.ok) saved += 1;
    }
    invalidateClientCache("/api/fnos/warehouses");
    invalidateClientCache("/api/fnos/products/master");
    setMessage(`창고 엑셀등록 완료: 저장 ${saved.toLocaleString("ko-KR")}건 / 스킵 ${skipped.toLocaleString("ko-KR")}건`);
    await loadWarehouses(query);
  }

  async function downloadWarehouses() {
    const params = new URLSearchParams({ page: "1", pageSize: "5000" });
    if (query.trim()) params.set("q", query.trim());
    const data = await cachedClientJson<{ warehouses?: FnWarehouse[]; ok?: boolean; error?: string }>(`/api/fnos/warehouses?${params.toString()}`, { ttl: 60_000, storageTtl: 5 * 60_000 }).catch((error) => ({ ok: false, error: error instanceof Error ? error.message : "창고정보 다운로드 실패", warehouses: [] }));
    if (data.ok === false) {
      setMessage(data.error || "창고정보 다운로드 실패");
      return;
    }
    const rows = (data.warehouses || []).map((warehouse) => [
      warehouse.warehouse_code || "",
      warehouse.warehouse_name || "",
      warehouse.warehouse_type_label || (warehouse.warehouse_type === "fulfillment" ? "풀필먼트" : "일반"),
      String(Number(warehouse.stock_product_count || 0)),
      warehouse.memo || "",
    ]);
    void downloadTableXlsx(`FN_OS_창고_${rows.length}건_${todayMmdd()}.xlsx`, "창고", ["창고코드", "창고명", "속성", "보유품목", "메모"], rows);
  }

  return (
    <div className="space-y-4">
      <Panel
        title="창고관리"
        subtitle={
          <div className="flex flex-wrap items-center gap-3 text-sm font-bold text-slate-500">
            <button type="button" className="font-black text-orange-600 underline underline-offset-4">전체창고</button>
            <span className="ml-2 rounded-lg bg-slate-100 px-3 py-1 font-black text-slate-900">창고수 {total.toLocaleString("ko-KR")}개</span>
          </div>
        }
        action={
          <div className="flex flex-wrap gap-2">
            <ActionButton type="button" onClick={openNewWarehouse}>F2 새 창고</ActionButton>
            <ActionButton type="button" variant="secondary" onClick={() => fileInputRef.current?.click()}>엑셀등록</ActionButton>
            <ActionButton type="button" variant="secondary" onClick={() => void downloadWarehouses()}>창고정보 다운로드</ActionButton>
            <button type="button" onClick={downloadWarehouseTemplate} className="inline-flex h-11 w-11 items-center justify-center rounded-md border-0 bg-transparent p-0 text-emerald-600 hover:bg-orange-50" aria-label="엑셀폼 다운로드" title="엑셀폼 다운로드">
              <ExcelFormIcon />
            </button>
            <input ref={fileInputRef} type="file" accept=".xlsx,.xls" className="hidden" onChange={(event) => {
              const file = event.target.files?.[0];
              if (file) void uploadWarehouses(file);
              event.target.value = "";
            }} />
          </div>
        }
      >
        <div className="mb-3 flex flex-wrap items-center justify-between gap-2">
          <div className="flex flex-wrap items-center gap-2">
            <ActionButton type="button" variant="secondary" onClick={() => setWarehouseBulkOpen(true)}>수정</ActionButton>
            <span className="text-xs font-bold text-slate-500">선택 {selectedWarehouseKeys.length.toLocaleString("ko-KR")}개</span>
          </div>
          <input className="field-input w-full max-w-sm rounded-md border border-slate-200 px-3 py-2 text-sm" value={query} onChange={(event) => setQuery(event.target.value)} placeholder="창고명 / 코드 검색" />
        </div>
        <div className="fn-table-shell overflow-x-auto [&_td:first-child]:pl-4 [&_td:last-child]:pr-4 [&_th:first-child]:pl-4 [&_th:last-child]:pr-4">
          <table className="w-full min-w-[980px] table-fixed text-sm">
            <thead className="border-b border-gray-200 bg-gray-50 text-xs font-semibold text-gray-500">
              <tr>
                <th className="w-20 py-2 text-center">
                  <input
                    type="checkbox"
                    className="h-5 w-5"
                    checked={warehouseSelection.allSelected}
                    onChange={(event) => warehouseSelection.toggleAll(event.target.checked)}
                    aria-label="창고 전체선택"
                  />
                </th>
                <th className="w-36 py-2 pl-4 text-left">창고 코드</th>
                <th className="w-56 py-2 text-left">창고명</th>
                <th className="w-28 py-2 text-left">창고 속성</th>
                <th className="w-24 py-2 text-left">보유 품목</th>
                <th className="w-80 py-2 text-left">메모</th>
              </tr>
            </thead>
            <tbody>
              {warehouses.map((warehouse, index) => {
                const key = warehouseRowKey(warehouse);
                const selected = selectedWarehouseKeys.includes(key);
                return (
                  <tr key={warehouse.id || warehouse.warehouse_code} onClick={() => openWarehouse(warehouse)} className={`cursor-pointer border-b border-gray-100 ${selected ? "bg-sky-50" : "hover:bg-orange-50/60"}`}>
                    <td className="py-2 text-center" onClick={(event) => event.stopPropagation()}>
                      <SelectionNumberButton index={index} selected={selected} onMouseDown={(event) => warehouseSelection.beginSelection(key, index, event)} onMouseEnter={() => warehouseSelection.continueSelection(key, index)} />
                    </td>
                    <td className="truncate py-2 pl-4 font-black">{warehouse.warehouse_code || "-"}</td>
                    <td className="truncate py-2 font-bold" title={warehouse.warehouse_name || ""}>{warehouse.warehouse_name || "-"}</td>
                    <td className="truncate py-2 text-slate-500">{warehouse.warehouse_type_label || warehouseAttributeLabel(warehouse.warehouse_type)}</td>
                    <td className="py-2 text-left font-black">{Number(warehouse.stock_product_count || 0).toLocaleString("ko-KR")}</td>
                    <td className="truncate py-2 text-slate-500" title={warehouse.memo || ""}>{warehouse.memo ? `${warehouse.memo.slice(0, 20)}${warehouse.memo.length > 20 ? "..." : ""}` : "-"}</td>
                  </tr>
                );
              })}
            </tbody>
          </table>
          {!warehouses.length && <EmptyState title={loading ? "" : "창고가 없습니다."} />}
        </div>
      </Panel>

      {warehouseBulkOpen && (
        <BulkMultiEditModal<WarehouseBulkField, FnWarehouse>
          title="창고 선택수정"
          description={`선택 ${selectedWarehouses.length.toLocaleString("ko-KR")}개 창고의 값을 수정합니다.`}
          fields={warehouseBulkFields}
          selectedFields={warehouseBulkSelectedFields}
          setSelectedFields={setWarehouseBulkSelectedFields}
          fieldPickerOpen={warehouseBulkFieldPickerOpen}
          setFieldPickerOpen={setWarehouseBulkFieldPickerOpen}
          commonField={warehouseBulkCommonField}
          setCommonField={setWarehouseBulkCommonField}
          commonValue={warehouseBulkCommonValue}
          setCommonValue={setWarehouseBulkCommonValue}
          rowDrafts={warehouseBulkDrafts}
          setRowDrafts={setWarehouseBulkDrafts}
          rows={selectedWarehouses}
          rowKeys={selectedWarehouses.map(warehouseRowKey)}
          selectedRowKeys={selectedWarehouseKeys}
          setSelectedRowKeys={setSelectedWarehouseKeys}
          getRowKey={warehouseRowKey}
          getRowName={(warehouse) => String(warehouse.warehouse_name || "-")}
          getRowSubLabel={(warehouse) => String(warehouse.warehouse_code || "-")}
          getCurrentValue={(warehouse, field) => {
            if (field === "warehouse_type") return normalizeWarehouseAttribute(warehouse.warehouse_type);
            if (field === "warehouse_name") return String(warehouse.warehouse_name || "");
            return String(parseWarehouseMemo(warehouse.memo)[field] || "");
          }}
          onClose={() => setWarehouseBulkOpen(false)}
          onSave={() => void saveWarehouseBulkEdit()}
        />
      )}

      {modalOpen && (
        <FormModal
          title={draft.id ? "창고 수정" : "새 창고"}
          description="속성, 창고코드, 창고명은 필수입니다."
          onClose={() => setModalOpen(false)}
          size="xl"
          footer={
            <>
              {draft.id && <ActionButton type="button" variant="secondary" className="mr-auto border-rose-200 text-rose-600 hover:bg-rose-50" onClick={() => void deleteWarehouseDraft()}>삭제</ActionButton>}
              <ActionButton type="button" variant="secondary" onClick={() => setModalOpen(false)}>닫기</ActionButton>
              <ActionButton type="button" onClick={() => void saveWarehouseDraft()}>저장</ActionButton>
            </>
          }
        >
          <div className="space-y-5">
            <div>
              <div className="mb-2 text-[13px] font-semibold text-gray-700">속성 선택 <span className="text-[#ff6a00]">*</span></div>
              <div className="flex flex-wrap gap-2">
              {[
                ["general", "일반"],
                ["fulfillment", "풀필먼트"],
              ].map(([value, label]) => (
                <button
                  key={value}
                  type="button"
                  onClick={() => updateDraft("warehouse_type", value)}
                  className={`h-10 rounded-md px-4 text-sm font-black ${draft.warehouse_type === value ? "bg-orange-500 text-white" : "border border-gray-200 bg-white text-slate-600 hover:bg-orange-50"}`}
                >
                  {label}
                </button>
              ))}
              </div>
            </div>
            <div className="grid gap-4 md:grid-cols-2">
              <FormField label="창고코드" required><input className={modalInputClass} value={draft.warehouse_code || ""} onChange={(event) => updateDraft("warehouse_code", event.target.value)} placeholder="100" /></FormField>
              <FormField label="창고명" required><input className={modalInputClass} value={draft.warehouse_name || ""} onChange={(event) => updateDraft("warehouse_name", event.target.value)} placeholder="에프엔 본사창고" /></FormField>
              <FormField label="창고 주소"><input className={modalInputClass} value={draft.warehouse_address || ""} onChange={(event) => updateDraft("warehouse_address", event.target.value)} placeholder="창고 주소" /></FormField>
              <FormField label="창고 연락처"><input className={modalInputClass} value={draft.warehouse_phone || ""} onChange={(event) => updateDraft("warehouse_phone", event.target.value)} placeholder="010-0000-0000" /></FormField>
              <FormField label="메모" className="md:col-span-2"><textarea className={modalTextareaClass} value={draft.memo || ""} onChange={(event) => updateDraft("memo", event.target.value)} placeholder="창고 관련 메모" /></FormField>
            </div>
            {draft.warehouse_type === "fulfillment" && (
              <div className="grid gap-4 border-t border-gray-200 pt-4 md:grid-cols-2">
                <div className="md:col-span-2 text-sm font-black text-slate-900">담당자 정보</div>
                <FormField label="담당자 이름"><input className={modalInputClass} value={draft.manager_name || ""} onChange={(event) => updateDraft("manager_name", event.target.value)} placeholder="담당자 이름" /></FormField>
                <FormField label="담당자 연락처"><input className={modalInputClass} value={draft.manager_phone || ""} onChange={(event) => updateDraft("manager_phone", event.target.value)} placeholder="담당자 연락처" /></FormField>
                <FormField label="메모" className="md:col-span-2"><textarea className={modalTextareaClass} value={draft.manager_memo || ""} onChange={(event) => updateDraft("manager_memo", event.target.value)} placeholder="풀필먼트 담당자 관련 메모" /></FormField>
              </div>
            )}
          </div>
        </FormModal>
      )}
    </div>
  );
}

function CustomerEditModal({
  draft,
  channelDraft,
  channelCredentials,
  credentialMeta,
  credentialsRevealed,
  channelLoading,
  onClose,
  onChange,
  onChannelChange,
  onCredentialChange,
  onRevealCredentials,
  onSave,
  onDelete,
}: {
  draft: Record<string, string>;
  channelDraft: SalesChannelDraft;
  channelCredentials: Record<(typeof salesChannelCredentialKeys)[number], string>;
  credentialMeta: Record<string, SalesChannelCredentialMeta>;
  credentialsRevealed: boolean;
  channelLoading: boolean;
  onClose: () => void;
  onChange: (key: string, value: string) => void;
  onChannelChange: (key: string, value: string) => void;
  onCredentialChange: (key: string, value: string) => void;
  onRevealCredentials: () => void;
  onSave: () => void;
  onDelete: () => void;
}) {
  useEscapeToClose(true, onClose);
  const customerType = normalizeCustomerAttribute(draft.customer_type);
  const businessSameAsCode = Boolean(draft.customer_code && draft.business_no && draft.business_no === formatBusinessNoInput(draft.customer_code));
  const [addressSearchOpen, setAddressSearchOpen] = useState(false);
  const detailAddressInputRef = useRef<HTMLInputElement | null>(null);

  function changeBusinessSameAsCode(checked: boolean) {
    onChange("business_no", checked ? draft.customer_code || "" : "");
  }

  function applyPostcode(data: DaumPostcodeData) {
    onChange("postal_code", String(data.zonecode || "").trim());
    onChange("road_address", daumRoadAddressWithExtra(data));
    onChange("jibun_address", String(data.jibunAddress || data.autoJibunAddress || "").trim());
    setAddressSearchOpen(false);
    window.setTimeout(() => detailAddressInputRef.current?.focus(), 0);
  }

  return (
    <FormModal
      title={draft.id ? "거래처 수정" : "새 거래처 등록"}
      onClose={onClose}
      size="xl"
      footer={
        <div className="flex w-full justify-between gap-2">
          <div>{draft.id && <ActionButton type="button" variant="danger" onClick={onDelete}>삭제</ActionButton>}</div>
          <div className="flex gap-2">
            <ActionButton type="button" variant="secondary" onClick={onClose}>닫기</ActionButton>
            <ActionButton type="button" onClick={onSave}>저장</ActionButton>
          </div>
        </div>
      }
    >
        <div className="space-y-4">
          <div>
            <div className="mb-2 text-[13px] font-semibold text-gray-700">속성 선택 <span className="text-[#ff6a00]">*</span></div>
            <div className="flex gap-2">
              {[
                { key: "general" as CustomerAttribute, label: "일반" },
                { key: "shopping" as CustomerAttribute, label: "쇼핑몰" },
              ].map((item) => (
                <button
                  key={item.key}
                  type="button"
                  onClick={() => onChange("customer_type", item.key)}
                  className={`h-10 rounded-lg border px-4 text-sm font-semibold ${customerType === item.key ? "border-orange-200 bg-orange-50 text-orange-700" : "border-gray-200 bg-white text-gray-500 hover:bg-gray-50"}`}
                >
                  {item.label}
                </button>
              ))}
            </div>
          </div>
          <div className="space-y-4">
            <div className="grid gap-4 md:grid-cols-2">
              <FormField label="거래처코드" required><input className={modalInputClass} value={draft.customer_code || ""} onChange={(event) => onChange("customer_code", event.target.value)} /></FormField>
              <FormField label="거래처명" required><input className={modalInputClass} value={draft.customer_name || ""} onChange={(event) => onChange("customer_name", event.target.value)} /></FormField>
            </div>
            <div className="grid gap-4 md:grid-cols-2">
              <FormField label="사업자등록번호">
                <input className={modalInputClass} inputMode="numeric" value={draft.business_no || ""} onChange={(event) => onChange("business_no", event.target.value)} placeholder="111-11-11111" />
                <span className="mt-2 flex items-center gap-2 text-[11px] font-bold text-slate-500">
                  <input type="checkbox" checked={businessSameAsCode} onChange={(event) => changeBusinessSameAsCode(event.target.checked)} />
                  거래처 코드와 동일
                </span>
              </FormField>
              <FormField label="팩스번호"><input className={modalInputClass} inputMode="numeric" value={draft.fax || ""} onChange={(event) => onChange("fax", event.target.value)} placeholder="031-000-0000" /></FormField>
            </div>
            <div className="grid gap-4 md:grid-cols-3">
              <FormField label="담당자명"><input className={modalInputClass} value={draft.contact_name || ""} onChange={(event) => onChange("contact_name", event.target.value)} placeholder="담당자명" /></FormField>
              <FormField label="전화번호"><input className={modalInputClass} inputMode="numeric" value={draft.phone || ""} onChange={(event) => onChange("phone", event.target.value)} placeholder="010-0000-0000" /></FormField>
              <FormField label="이메일"><input className={modalInputClass} type="email" value={draft.email || ""} onChange={(event) => onChange("email", event.target.value)} placeholder="name@example.com" /></FormField>
            </div>
            <FormField label="주소">
              <div className="grid gap-2">
                <div className="grid gap-2 md:grid-cols-[120px_180px_1fr]">
                  <ActionButton type="button" variant="secondary" onClick={() => setAddressSearchOpen(true)}>주소검색</ActionButton>
                  <input className={modalInputClass} value={draft.postal_code || ""} readOnly placeholder="우편번호" />
                  <input ref={detailAddressInputRef} className={modalInputClass} value={draft.detail_address || ""} onChange={(event) => onChange("detail_address", event.target.value)} placeholder="상세주소" />
                </div>
                <input className={modalInputClass} value={composeCustomerAddress(draft)} readOnly placeholder="주소" />
              </div>
            </FormField>
            <FormField label="메모"><textarea className={modalTextareaClass} value={draft.memo || ""} onChange={(event) => onChange("memo", event.target.value)} /></FormField>
          </div>
          {customerType === "shopping" && (
            <div className="rounded-xl border border-orange-100 bg-orange-50/40 p-4">
              <div className="mb-3 flex flex-wrap items-center justify-between gap-2">
                <div>
                  <div className="text-sm font-semibold text-orange-700">쇼핑몰 API 정보</div>
                  <p className="mt-1 text-xs font-medium text-orange-700">주문수집에서 사용할 쇼핑몰 채널과 credential을 연결합니다.</p>
                </div>
                <ActionButton type="button" variant="secondary" className="h-8 border-orange-200 px-3 text-xs text-orange-700 hover:bg-orange-50" onClick={onRevealCredentials} disabled={channelLoading}>
                  {credentialsRevealed ? "가리기" : "보기"}
                </ActionButton>
              </div>
              <div className="grid gap-4 md:grid-cols-2">
                <FormField label="channel_code"><input className={modalInputClass} value={channelDraft.channel_code || ""} onChange={(event) => onChannelChange("channel_code", event.target.value)} placeholder="NAVER" /></FormField>
                <FormField label="channel_name"><input className={modalInputClass} value={channelDraft.channel_name || ""} onChange={(event) => onChannelChange("channel_name", event.target.value)} placeholder="네이버 스마트스토어" /></FormField>
                <FormField label="seller_id"><input className={modalInputClass} value={channelDraft.seller_id || ""} onChange={(event) => onChannelChange("seller_id", event.target.value)} /></FormField>
                <FormField label="seller_site_url"><input className={modalInputClass} value={channelDraft.seller_site_url || ""} onChange={(event) => onChannelChange("seller_site_url", event.target.value)} placeholder="https://..." /></FormField>
                <FormField label="api_enabled">
                  <select className={modalSelectClass} value={channelDraft.api_enabled || "false"} onChange={(event) => onChannelChange("api_enabled", event.target.value)}>
                    <option value="false">N</option>
                    <option value="true">Y</option>
                  </select>
                </FormField>
                <FormField label="api_status">
                  <select className={modalSelectClass} value={channelDraft.api_status || "manual"} onChange={(event) => onChannelChange("api_status", event.target.value)}>
                    <option value="manual">manual</option>
                    <option value="planned">planned</option>
                    <option value="ready">ready</option>
                    <option value="connected">connected</option>
                    <option value="error">error</option>
                  </select>
                </FormField>
                {salesChannelCredentialKeys.map((key) => {
                  const meta = credentialMeta[key];
                  const placeholder = meta?.has_value ? meta.hint || "****" : "";
                  return (
                    <FormField key={key} label={salesChannelCredentialLabels[key]}>
                      <input
                        className={modalInputClass}
                        type={credentialsRevealed ? "text" : "password"}
                        value={channelCredentials[key] || ""}
                        onChange={(event) => onCredentialChange(key, event.target.value)}
                        placeholder={placeholder}
                      />
                    </FormField>
                  );
                })}
              </div>
              <p className="mt-3 text-xs font-medium leading-relaxed text-orange-700">
                저장된 secret은 평문으로 기본 표시하지 않습니다. 값이 있는 항목은 hint만 보이고, 새 값을 입력한 항목만 저장 시 갱신됩니다.
              </p>
            </div>
          )}
        </div>
        {addressSearchOpen && <DaumPostcodeModal onClose={() => setAddressSearchOpen(false)} onSelect={applyPostcode} />}
    </FormModal>
  );
}

function ProductEditModal({
  draft,
  warehouses,
  bomRows,
  importLinks,
  onClose,
  onChange,
  onBomRowsChange,
  onSave,
  onDelete,
}: {
  draft: Record<string, string>;
  warehouses: WarehouseOption[];
  bomRows: ProductBomRow[];
  importLinks: ProductImportLinkRow[];
  onClose: () => void;
  onChange: (key: string, value: string) => void;
  onBomRowsChange: (rows: ProductBomRow[]) => void;
  onSave: () => void;
  onDelete: () => void;
}) {
  const [componentQuery, setComponentQuery] = useState("");
  const [componentCandidates, setComponentCandidates] = useState<FnProduct[]>([]);
  const [bomOpen, setBomOpen] = useState(false);
  const productAttribute = normalizeProductAttribute(draft.product_attribute || draft.product_kind);
  const showBomPanel = productAttribute === "set" || bomRows.length > 0 || bomOpen;
  useEscapeToClose(true, onClose);

  useEffect(() => {
    const keyword = componentQuery.trim() || (productAttribute === "set" ? relatedProductSearchQuery(draft.product_name) : "");
    if (!keyword) {
      setComponentCandidates([]);
      return;
    }
    let alive = true;
    const timer = window.setTimeout(async () => {
      const params = new URLSearchParams({ q: keyword, page: "1", pageSize: "20", excludeBom: "true" });
      const data = await cachedClientJson<{ products?: FnProduct[] }>(`/api/fnos/products/master?${params.toString()}`, { ttl: 5 * 60_000, storageTtl: 10 * 60_000 }).catch(() => ({ products: [] }));
      if (alive) {
        setComponentCandidates((data.products || []).filter((product: FnProduct) => (
          product.id !== draft.id && !bomRows.some((row) => row.component_product_id === product.id)
        )));
      }
    }, 250);
    return () => {
      alive = false;
      window.clearTimeout(timer);
    };
  }, [componentQuery, draft.id, draft.product_name, productAttribute, bomRows]);

  function addBomComponent(product: FnProduct) {
    if (!product.id) return;
    if (product.id === draft.id) return;
    if (bomRows.some((row) => row.component_product_id === product.id)) return;
    onBomRowsChange([
      ...bomRows,
      {
        component_product_id: product.id,
        component_sku: product.product_code || product.sku,
        component_product_code: product.product_code || product.sku,
        component_product_name: product.product_name,
        qty_per_unit: 1,
      },
    ]);
    setComponentQuery("");
    setComponentCandidates([]);
  }

  function updateBomQty(index: number, value: string) {
    onBomRowsChange(bomRows.map((row, rowIndex) => rowIndex === index ? { ...row, qty_per_unit: Number(value) || 0 } : row));
  }

  function removeBomComponent(index: number) {
    onBomRowsChange(bomRows.filter((_, rowIndex) => rowIndex !== index));
  }

  function selectProductAttribute(attribute: ProductAttribute) {
    onChange("product_attribute", attribute);
    onChange("product_kind", attribute);
    onChange("product_name", productNameWithAttribute(draft.product_name || "", attribute));
    if (attribute === "set") setBomOpen(true);
  }

  return (
    <FormModal
      title={draft.id ? "품목 수정" : "새 품목 등록"}
      onClose={onClose}
      size="lg"
      footer={
        <div className="flex w-full justify-between gap-2">
          <div>{draft.id && <ActionButton type="button" variant="danger" onClick={onDelete}>삭제</ActionButton>}</div>
          <div className="flex gap-2">
            <ActionButton type="button" variant="secondary" onClick={onClose}>닫기</ActionButton>
            <ActionButton type="button" onClick={onSave}>저장</ActionButton>
          </div>
        </div>
      }
    >
      <div className="space-y-5">
        <div className="space-y-3">
          <div className="flex flex-wrap gap-2">
            {(["plain", "set", "rg"] as ProductAttribute[]).map((attribute) => {
              const selected = normalizeProductAttribute(draft.product_attribute || draft.product_kind) === attribute;
              return (
                <button
                  key={attribute}
                  type="button"
                  onClick={() => selectProductAttribute(attribute)}
                  className={`rounded-md border px-4 py-2 text-sm font-black ${
                    selected ? "border-slate-950 bg-slate-950 text-white" : "border-slate-200 bg-white text-slate-600 hover:border-orange-300 hover:text-orange-600"
                  }`}
                >
                  {productAttributeLabel(attribute)}
                </button>
              );
            })}
          </div>
        </div>
        <div className="grid gap-4 md:grid-cols-2">
          <FormField label="품목코드" required><input className={modalInputClass} value={draft.product_code || ""} onChange={(event) => onChange("product_code", event.target.value)} /></FormField>
          <FormField label="품목명" required><input className={modalInputClass} value={draft.product_name || ""} onChange={(event) => onChange("product_name", event.target.value)} /></FormField>
          <FormField label="입고가"><input className={modalInputClass} type="number" value={draft.cost_price || ""} onChange={(event) => onChange("cost_price", event.target.value)} /></FormField>
          <FormField label="출고가"><input className={modalInputClass} type="number" value={draft.standard_price || ""} onChange={(event) => onChange("standard_price", event.target.value)} /></FormField>
        </div>
        <div className="rounded-xl border border-gray-200 p-4">
          <div className="mb-3 text-sm font-semibold text-gray-900">재고등록(수정)</div>
          <div className="grid gap-2 md:grid-cols-2">
            {warehouses.map((warehouse) => (
              <label key={warehouse.id || warehouse.warehouse_code} className="text-xs font-black text-slate-500">
                <span className="flex items-center justify-between gap-2">
                  <span className="truncate">{warehouse.warehouse_code} - {warehouse.warehouse_name}</span>
                  <span className="shrink-0 rounded bg-slate-100 px-2 py-0.5 text-[11px] text-slate-600">현재 {Number(draft[`stock_${warehouse.warehouse_code}`] || 0).toLocaleString("ko-KR")}</span>
                </span>
                <input
                  className={modalInputClass}
                  type="number"
                  value={draft[`stock_${warehouse.warehouse_code}`] || ""}
                  placeholder="수정 수량"
                  onChange={(event) => onChange(`stock_${warehouse.warehouse_code}`, event.target.value)}
                />
              </label>
            ))}
            {!warehouses.length && <div className="rounded-md bg-slate-50 p-4 text-sm font-bold text-slate-400">등록된 창고가 없습니다. 먼저 창고관리에서 창고를 등록해 주세요.</div>}
          </div>
        </div>
        {!showBomPanel && (
          <div className="rounded-xl border border-dashed border-gray-200 p-4">
            <ActionButton type="button" variant="secondary" onClick={() => setBomOpen(true)}>BOM 설정</ActionButton>
          </div>
        )}
        {showBomPanel && <div className="rounded-xl border border-gray-200 p-4">
          <div className="mb-3 flex items-center justify-between gap-3">
            <div>
              <div className="text-sm font-semibold text-gray-900">BOM 관리</div>
              <p className="mt-1 text-xs font-medium text-gray-500">세트 판매품이면 실제 차감될 구성 품목과 수량을 지정합니다.</p>
            </div>
            <span className="rounded bg-emerald-50 px-2 py-1 text-xs font-black text-emerald-700">{bomRows.length}개 구성</span>
          </div>
          <input
            className={`${modalInputClass} mb-2`}
            value={componentQuery}
            onChange={(event) => setComponentQuery(event.target.value)}
            placeholder="구성품 품목코드 / 품목명 검색"
          />
          {!!componentCandidates.length && (
            <div className="mb-3 max-h-36 overflow-auto rounded-xl border border-gray-200">
              {componentCandidates.map((product) => (
                <button
                  key={product.id}
                  type="button"
                  onClick={() => addBomComponent(product)}
                  className="flex w-full items-center justify-between gap-3 border-b border-slate-100 px-3 py-2 text-left text-sm hover:bg-orange-50"
                >
                  <span className="font-black">{product.product_code || product.sku}</span>
                  <span className="flex-1 truncate font-bold text-slate-600">{product.product_name}</span>
                  <span className="text-xs font-black text-orange-600">선택</span>
                </button>
              ))}
            </div>
          )}
          <div className="space-y-2">
            {bomRows.map((row, index) => (
              <div key={`${row.component_product_id}-${index}`} className="grid items-center gap-2 rounded-lg bg-gray-50 p-2 md:grid-cols-[120px_1fr_90px_64px]">
                <div className="text-sm font-black">{row.component_product_code || row.component_sku}</div>
                <div className="truncate text-sm font-bold text-slate-600">{row.component_product_name || "-"}</div>
                <input className={`${modalInputClass} h-8 text-right`} type="number" min="0" step="1" value={row.qty_per_unit || ""} onChange={(event) => updateBomQty(index, event.target.value)} />
                <ActionButton type="button" variant="secondary" className="h-8 border-rose-200 px-2 text-xs text-rose-600 hover:bg-rose-50" onClick={() => removeBomComponent(index)}>삭제</ActionButton>
              </div>
            ))}
            {!bomRows.length && <div className="rounded-md bg-slate-50 p-4 text-sm font-bold text-slate-400">BOM 구성품이 없습니다.</div>}
          </div>
        </div>}
        <div className="rounded-xl border border-gray-200 p-4">
          <div className="mb-3 flex items-center justify-between gap-3">
            <div className="text-sm font-semibold text-gray-900">수입관리 연동</div>
            <ActionButton type="button" variant="secondary" className="h-8 border-orange-200 px-3 text-xs text-orange-700 hover:bg-orange-50" onClick={() => goToInternal(importHref("/products"))}>수입관리에서 수정</ActionButton>
          </div>
          <div className="space-y-2">
            {importLinks.map((link, index) => (
              <div key={`${link.import_product_id}-${index}`} className="rounded-md bg-orange-50 px-3 py-2 text-sm font-bold text-orange-800">
                {link.import_product_name || `수입상품 ${link.import_product_id || ""}`}
                {link.import_option_name ? ` / ${link.import_option_name}` : ""}
              </div>
            ))}
            {!importLinks.length && <div className="rounded-md bg-slate-50 p-4 text-sm font-bold text-slate-400">연동된 수입관리 상품이 없습니다.</div>}
          </div>
        </div>
      </div>
    </FormModal>
  );
}

function MasterEntryPanel({ config, setMessage, loadSummary }: { config: (typeof masterTabs)[number]; setMessage: (value: string) => void; loadSummary: () => void }) {
  const [draft, setDraft] = useState<Record<string, string>>({});
  const [uploading, setUploading] = useState(false);

  function invalidateMasterEntryCaches() {
    if (config.key === "customers") {
      invalidateClientCache("/api/fnos/customers");
      invalidateClientCache("/api/fnos/sales-channels");
    }
    if (config.key === "products") {
      invalidateClientCache("/api/fnos/products/master");
      invalidateClientCache("/api/fnos/products/search");
      invalidateClientCache("/api/fnos/products");
    }
    if (config.key === "warehouses") {
      invalidateClientCache("/api/fnos/products/master");
    }
    if (config.key === "channels") {
      invalidateClientCache("/api/fnos/sales-channels");
    }
    invalidateClientCache("/api/dashboard/summary");
  }

  useEffect(() => {
    setDraft(Object.fromEntries(config.templateHeaders.slice(0, 6).map((header) => [header, ""])));
  }, [config.key]);

  function updateField(header: string, value: string) {
    setDraft((prev) => ({ ...prev, [header]: value }));
  }

  function downloadTemplate() {
    void downloadTableXlsx(`FN_OS_${config.title}_업로드_서식.xlsx`, `${config.title}업로드`, config.templateHeaders, [config.sampleRow]);
  }

  async function saveRows(rows: Record<string, unknown>[]) {
    if (config.key === "products") {
      let success = 0;
      for (const row of rows) {
        const res = await fetch("/api/fnos/quick-register", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          credentials: "include",
          body: JSON.stringify({
            mode: "product",
            form: {
              prod_cd: row["품목코드"],
              product_code: row["품목코드"],
              prod_name: row["품목명"],
              product_name: row["품목명"],
              size_des: row["옵션"],
              out_price: row["표준단가"],
              in_price: row["매입단가"],
            },
          }),
        });
        if (res.ok) success += 1;
      }
      setMessage(`품목 ${success}건을 저장했습니다.`);
      invalidateMasterEntryCaches();
      return;
    }

    if (config.key === "channels") {
      const res = await fetch("/api/fnos/sales-channels", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        credentials: "include",
        body: JSON.stringify({ rows }),
      });
      const data = await res.json().catch(() => ({}));
      setMessage(res.ok && data.ok !== false ? `쇼핑몰 ${data.count || rows.length}건을 저장했습니다.` : data.error || "쇼핑몰 저장 실패");
      invalidateMasterEntryCaches();
      loadSummary();
      return;
    }

    if (config.key === "warehouses") {
      let success = 0;
      for (const row of rows) {
        const res = await fetch("/api/fnos/quick-register", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          credentials: "include",
          body: JSON.stringify({
            mode: "warehouse",
            form: {
              wh_cd: row["창고코드"],
              warehouse_code: row["창고코드"],
              wh_name: row["창고명"],
              warehouse_name: row["창고명"],
              warehouse_type: row["창고구분"],
              memo: row["메모"],
            },
          }),
        });
        if (res.ok) success += 1;
      }
      setMessage(`창고 ${success}건을 저장했습니다.`);
      invalidateMasterEntryCaches();
      return;
    }

  }

  async function uploadExcel(file: File) {
    setUploading(true);
    try {
      if (config.uploadEndpoint) {
        const form = new FormData();
        form.append("file", file);
        const res = await fetch(config.uploadEndpoint, { method: "POST", credentials: "include", body: form });
        const data = await res.json().catch(() => ({}));
        setMessage(res.ok && data.ok !== false ? `${config.title} ${data.count || 0}건을 업로드했습니다.` : data.error || `${config.title} 업로드 실패`);
        if (res.ok && data.ok !== false) invalidateMasterEntryCaches();
        return;
      }
      const rows = await readXlsxObjects(file);
      await saveRows(rows);
    } catch (error) {
      setMessage(error instanceof Error ? error.message : `${config.title} 업로드 실패`);
    } finally {
      setUploading(false);
    }
  }

  async function saveDraft() {
    const row = { ...draft };
    if (config.key === "customers") {
      const res = await fetch("/api/fnos/quick-register", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        credentials: "include",
        body: JSON.stringify({
          mode: "customer",
          form: {
            cust_code: row["거래처코드"],
            cust_name: row["거래처명"],
            business_no: row["사업자번호"],
            contact_name: row["담당자"],
            phone: row["전화"],
            memo: row["메모"],
          },
        }),
      });
      const data = await res.json().catch(() => ({}));
      setMessage(res.ok && data.ok !== false ? "거래처를 저장했습니다." : data.error || "거래처 저장 실패");
      if (res.ok && data.ok !== false) invalidateMasterEntryCaches();
      return;
    }
    await saveRows([row]);
  }

  return (
    <Panel
      title={`${config.title} 입력`}
      subtitle="개별 입력 또는 엑셀 업로드로 기초 데이터를 관리합니다."
      action={
        <div className="flex flex-wrap gap-2">
          <button type="button" onClick={downloadTemplate} className="inline-flex h-11 w-11 items-center justify-center rounded-md border-0 bg-transparent p-0 text-emerald-600 hover:bg-orange-50" aria-label="엑셀폼 다운로드" title="엑셀폼 다운로드"><ExcelFormIcon /></button>
          <label className="inline-flex h-10 cursor-pointer items-center rounded-md border border-orange-200 bg-orange-50 px-4 text-sm font-black text-orange-600">
            {"엑셀 업로드"}
            <input type="file" accept=".xlsx,.xls" className="hidden" onChange={(event) => {
              const file = event.target.files?.[0];
              if (file) void uploadExcel(file);
              event.target.value = "";
            }} />
          </label>
        </div>
      }
    >
      <div className="grid gap-2 md:grid-cols-3">
        {config.templateHeaders.slice(0, 6).map((header) => (
          <input
            key={`${config.key}-${header}`}
            className="field-input rounded-md border border-slate-200 px-3 py-2 text-sm"
            placeholder={header}
            value={draft[header] || ""}
            onChange={(event) => updateField(header, event.target.value)}
          />
        ))}
      </div>
      <div className="mt-3 flex justify-end">
        <button type="button" onClick={() => void saveDraft()} className="rounded-md bg-slate-950 px-4 py-2 text-sm font-black text-white">개별 입력 저장</button>
      </div>
    </Panel>
  );
}

function SalesInventoryTable({
  rows,
  lineRows = [],
  mode,
  onChanged,
  onEditEntry,
  topLeft,
  topRight,
  filterBar,
}: {
  rows: Array<Record<string, unknown>>;
  lineRows?: Array<Record<string, unknown>>;
  mode: SalesPurchaseMode;
  onChanged: () => void;
  onEditEntry: (row: Record<string, unknown>) => void;
  topLeft?: ReactNode;
  topRight?: ReactNode;
  filterBar?: ReactNode;
}) {
  const [selectedKeys, setSelectedKeys] = useState<string[]>([]);
  const rowKeys = rows.map((row, index) => entryRowKey(row, mode, index));
  const selection = useCheckboxColumnSelection({ keys: rowKeys, selectedKeys, setSelectedKeys });
  const entryNumbers = new Map<string, string>();
  const dateCounts = new Map<string, number>();
  rows.forEach((row, index) => {
    const date = entryDateFilterKey(entryRowDate(row)) || entryDateToday().replace(/\D/g, "");
    const next = (dateCounts.get(date) || 0) + 1;
    dateCounts.set(date, next);
    entryNumbers.set(entryRowKey(row, mode, index), compactEntryNumber(date, next));
  });

  function selectedRows() {
    const set = new Set(selectedKeys);
    return rows.filter((row, index) => set.has(entryRowKey(row, mode, index)));
  }

  async function deleteSelected() {
    const targetRows = selectedRows();
    if (!targetRows.length) {
      window.alert("삭제할 행을 선택해 주세요.");
      return;
    }
    if (!window.confirm(`선택한 ${targetRows.length.toLocaleString("ko-KR")}건을 삭제할까요?`)) return;
    const endpoint = mode === "sales" ? "/api/sales/import" : "/api/purchases/import";
    const res = await fetch(endpoint, {
      method: "DELETE",
      headers: { "Content-Type": "application/json" },
      credentials: "include",
      body: JSON.stringify({ group_keys: targetRows.map((row) => entryRowKey(row, mode)) }),
    });
    const data = await res.json().catch(() => ({}));
    if (!res.ok || data.ok === false) {
      window.alert(data.error || "삭제 실패");
      return;
    }
    setSelectedKeys([]);
    onChanged();
  }

  function statementLines(row: Record<string, unknown>) {
    const key = entryRowKey(row, mode);
    const matches = lineRows.filter((line, index) => entryRowKey(line, mode, index) === key);
    return (matches.length ? matches : [row]).map((line) => {
      const qty = entryRowQty(line);
      const amount = entryRowAmount(line);
      const rawPrice = Number(line.price ?? line.unit_price ?? line.in_price ?? line.out_price ?? 0);
      return {
        productCode: entryRowProductCode(line),
        productName: entryRowProduct(line),
        qty,
        unitPrice: rawPrice || (qty ? amount / qty : 0),
        amount,
      };
    });
  }

  function normalizeStatementCustomerLookup(value: unknown) {
    return String(value || "").trim().toLowerCase().replace(/\s+/g, "").replace(/[()\[\]{}<>貴中귀중]/g, "");
  }

  function statementCustomerField(customer: Record<string, unknown> | null, keys: string[]) {
    for (const key of keys) {
      const value = String(customer?.[key] || "").trim();
      if (value) return value;
    }
    return "";
  }

  function statementCustomerRecord(customers: Array<Record<string, unknown>>, name: string) {
    const normalized = String(name || "").trim();
    const normalizedLoose = normalizeStatementCustomerLookup(normalized);
    if (!normalizedLoose) return null;
    return customers.find((customer) => {
      const candidates = [customer.customer_name, customer.cust_name, customer.customer_code, customer.cust_code, customer.business_no, customer.biz_no]
        .map((value) => String(value || "").trim())
        .filter(Boolean);
      return candidates.includes(normalized) || candidates.some((value) => {
        const loose = normalizeStatementCustomerLookup(value);
        return loose && (loose === normalizedLoose || loose.includes(normalizedLoose) || normalizedLoose.includes(loose));
      });
    }) || null;
  }

  async function fetchStatementCustomers() {
    const data = await fetch(`/api/fnos/customers?page=1&pageSize=5000&_=${Date.now()}`, { cache: "no-store", credentials: "include" })
      .then((res) => res.json())
      .catch(() => ({ customers: [] }));
    return Array.isArray(data.customers) ? data.customers as Array<Record<string, unknown>> : [];
  }

  function statementPageHtml(row: Record<string, unknown>, pageNumber: number, totalPages: number, company: FnCompanyInfo, customers: Array<Record<string, unknown>> = []) {
    const key = entryRowKey(row, mode);
    const lines = statementLines(row);
    const customerName = entryRowCustomer(row, mode);
    const receiver = statementCustomerRecord(customers, customerName);
    const receiverBusinessNo = statementCustomerField(receiver, ["business_no", "business_number", "biz_no", "registration_no"]);
    const receiverName = statementCustomerField(receiver, ["ceo_name", "representative_name", "owner_name", "president_name", "contact_name", "manager_name"]);
    const receiverPhone = statementCustomerField(receiver, ["phone", "tel", "telephone", "mobile", "contact_phone"]);
    const totalQty = lines.reduce((sum, line) => sum + line.qty, 0);
    const totalAmount = lines.reduce((sum, line) => sum + line.amount, 0);
    const roundedTotal = Math.round(totalAmount);
    const supply = Math.round(roundedTotal / 1.1);
    const vat = roundedTotal - supply;
    const statementLineLimit = 20;
    const rowsHtml = lines.slice(0, statementLineLimit).map((line) => `
      <tr>
        <td>${htmlEscape(line.productCode)}</td>
        <td class="left">${htmlEscape(line.productName)}</td>
        <td class="num">${line.qty.toLocaleString("ko-KR")}</td>
        <td class="num">${Math.round(line.unitPrice).toLocaleString("ko-KR")}</td>
        <td class="num">${Math.round(line.amount).toLocaleString("ko-KR")}</td>
        <td></td>
        <td></td>
      </tr>`).join("");
    const blankRows = Array.from({ length: Math.max(0, statementLineLimit - Math.min(statementLineLimit, lines.length)) }, () => `<tr class="blank"><td></td><td></td><td></td><td></td><td></td><td></td><td></td></tr>`).join("");
    const seal = company.seal_image_url ? `<img class="seal" src="${htmlEscape(company.seal_image_url)}" onerror="this.style.display='none'">` : "";
    const companyPhone = company.phone === "031-7675-455" ? "031-767-5455" : company.phone;
    return `<section class="page ${pageNumber === 1 ? "active" : ""}" data-page="${pageNumber}">
      <div class="statement-head">
        <h1>거래명세서</h1>
        <div class="receiver">
          <div>${htmlEscape(customerName)} 貴 中</div>
          <div>${htmlEscape(receiverBusinessNo)}</div>
          <div>${htmlEscape(receiverName)}</div>
          <div>${htmlEscape(receiverPhone)}</div>
          <div>날짜:${htmlEscape(entryDateFilterKey(entryRowDate(row)))}</div>
        </div>
        <table class="supplier"><tbody>
          <tr><th rowspan="4" class="vertical">공<br>급<br>자</th><th>일련번호</th><td>${htmlEscape(entryNumbers.get(key) || compactEntryNumber(entryRowDate(row), pageNumber))}</td><th>TEL</th><td>${htmlEscape(companyPhone)}</td></tr>
          <tr><th>사업자번호</th><td>${htmlEscape(company.business_no)}</td><th>성명</th><td class="seal-cell"><span class="rep-name">${htmlEscape(company.representative_name)}</span>${seal}</td></tr>
          <tr><th>상호</th><td colspan="3">${htmlEscape(company.company_name)}</td></tr>
          <tr><th>주소</th><td colspan="3">${htmlEscape(company.address)}</td></tr>
        </tbody></table>
      </div>
      <div class="amount-box"><span>금 액 : ${amountToKoreanText(roundedTotal)} 정</span><strong>(₩ ${roundedTotal.toLocaleString("ko-KR")})</strong></div>
      <table class="items"><thead><tr><th>품목코드</th><th>품목명[규격명]</th><th>수량</th><th>단가</th><th>합계</th><th>담당자</th><th>참조</th></tr></thead><tbody>${rowsHtml}${blankRows}
        <tr class="total"><th colspan="2">종합계</th><th class="num">${totalQty.toLocaleString("ko-KR")}</th><th></th><th class="num">${roundedTotal.toLocaleString("ko-KR")}</th><th></th><th></th></tr>
      </tbody></table>
      <table class="sum"><tbody><tr><th>수량</th><td>${totalQty.toLocaleString("ko-KR")}</td><th>공급가액</th><td class="num">${supply.toLocaleString("ko-KR")}</td><th>VAT</th><td class="num">${vat.toLocaleString("ko-KR")}</td><th>합계</th><td class="num">${roundedTotal.toLocaleString("ko-KR")}</td><th>인수</th><td>인</td></tr><tr><th>전잔액</th><td colspan="4">전잔:</td><td colspan="5"></td></tr></tbody></table>
      <div class="page-count">[${pageNumber}/${totalPages}]</div>
    </section>`;
  }

  function statementHtml(targetRows: Array<Record<string, unknown>>, autoPrint = false, customers: Array<Record<string, unknown>> = []) {
    const title = mode === "sales" ? "판매 거래명세서" : "구매 거래명세서";
    const company = getFnDocumentCompanyInfo();
    const pages = targetRows.length ? targetRows : [];
    const pagesHtml = pages.map((row, index) => statementPageHtml(row, index + 1, pages.length, company, customers)).join("");
    return `<!doctype html><html lang="ko"><head><meta charset="utf-8"><title>${title}</title><style>
      @page{size:A4 portrait;margin:10mm 10mm 8mm}
      *{box-sizing:border-box}body{margin:0;background:#fff;color:#111;font-family:Arial,"Malgun Gothic",sans-serif}
      .page{position:relative;width:190mm;min-height:279mm;margin:0 auto;display:none;padding-top:5mm}
      .page.active{display:block}
      h1{grid-column:1/3;margin:0 0 8mm;text-align:center;font-size:28px;letter-spacing:0;font-weight:900}
      .statement-head{display:grid;grid-template-columns:82mm 1fr;gap:5mm;align-items:start}
      .receiver{border:1.5px solid #111;min-height:31mm;padding:5mm;text-align:center;font-size:14px;line-height:1.7}
      .supplier{width:100%;border-collapse:collapse;font-size:12px}
      .supplier th,.supplier td{border:1px solid #111;padding:3px 5px;text-align:center;height:9mm}
      .supplier .vertical{width:8mm;font-size:14px;font-weight:900;line-height:1.5}
      .seal-cell{position:relative}.rep-name{position:relative;z-index:1;display:inline-block;min-width:20mm}.seal{position:absolute;right:-7px;top:calc(1mm - 5px);width:12mm;height:12mm;object-fit:contain;opacity:.78}
      .amount-box{display:flex;justify-content:space-between;align-items:center;border:2px solid #111;margin:3mm 0 2.5mm;padding:2mm 6mm;font-size:18px;font-weight:900}
      .items,.sum{width:100%;border-collapse:collapse;font-size:12px}.items{height:151mm}
      .items th,.items td,.sum th,.sum td{border:1px solid #8c8c8c;padding:2px 4px;text-align:center}
      .items th,.sum th{background:#f5f5f5}.items td{height:6.6mm}.left{text-align:left}.num{text-align:right}
      .items .total th,.items .total td{background:#f4f4f4;font-weight:900}
      .sum{margin-top:3mm}.sum td,.sum th{height:8mm}
      .toolbar{position:fixed;left:12px;bottom:12px;display:flex;align-items:center;gap:8px}
      .toolbar button{border:1px solid #d1d5db;background:#fff;border-radius:6px;padding:8px 12px;font-weight:700}
      .pager{min-width:64px;text-align:center;font-weight:800}.page-count{margin-top:4mm;text-align:right;font-size:12px;font-weight:700}
      @media print{.toolbar{display:none}.page{display:block;break-after:page;width:auto;min-height:279mm;margin:0}.page:last-of-type{break-after:auto}}
    </style></head><body>${pagesHtml}
      <div class="toolbar">
        <button id="prevPage" type="button">‹</button>
        <span id="pager" class="pager">1/${pages.length}</span>
        <button id="nextPage" type="button">›</button>
        <button onclick="window.print()">인쇄/PDF저장</button>
        <button onclick="window.close()">닫기</button>
      </div>
      <script>
        const pages = Array.from(document.querySelectorAll(".page"));
        let current = 0;
        function render() {
          pages.forEach((page, index) => page.classList.toggle("active", index === current));
          document.getElementById("pager").textContent = (current + 1) + "/" + pages.length;
          document.getElementById("prevPage").disabled = current === 0;
          document.getElementById("nextPage").disabled = current >= pages.length - 1;
        }
        document.getElementById("prevPage").onclick = () => { current = Math.max(0, current - 1); render(); };
        document.getElementById("nextPage").onclick = () => { current = Math.min(pages.length - 1, current + 1); render(); };
        render();
        ${autoPrint ? "window.addEventListener('load', () => setTimeout(() => window.print(), 250));" : ""}
      </script>
    </body></html>`;
  }

  async function openStatement(targetRows: Array<Record<string, unknown>>, autoPrint = false) {
    const popup = window.open("", "_blank", "width=980,height=900");
    if (!popup) return;
    popup.document.write("<!doctype html><html lang=\"ko\"><head><meta charset=\"utf-8\"><title>거래명세서</title></head><body>거래명세서를 준비 중입니다.</body></html>");
    popup.document.close();
    const customers = await fetchStatementCustomers();
    popup.document.open();
    popup.document.write(statementHtml(targetRows, autoPrint, customers));
    popup.document.close();
  }

  function emailStatement(targetRows: Array<Record<string, unknown>>) {
    const customers = Array.from(new Set(targetRows.map((row) => entryRowCustomer(row, mode).trim()).filter(Boolean)));
    if (customers.length !== 1) {
      window.alert("E-mail은 거래처 한 곳의 전표만 보낼 수 있습니다.");
      return;
    }
    const fallback = window.prompt("거래처 이메일 주소를 입력해 주세요.", String(targetRows[0]?.email || ""));
    if (!fallback) return;
    const firstDate = entryDateFilterKey(entryRowDate(targetRows[0] || {})).slice(2) || entryDateToday().replace(/\D/g, "").slice(2);
    const subject = `${firstDate} - ${mode === "sales" ? "판매" : "구매"} 거래명세서 - 에프엔`;
    const body = `안녕하세요.\n\n${subject} PDF 거래명세서를 전달드립니다.\n거래명세서 PDF는 FN OS의 PDF 버튼에서 저장한 파일을 첨부해 주세요.\n\n감사합니다.\n에프엔`;
    window.location.href = `mailto:${encodeURIComponent(fallback)}?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;
  }

  const partnerLabel = mode === "sales" ? "거래처" : "구매처";
  return (
    <>
      <div className="mb-2 flex items-center gap-3 whitespace-nowrap pb-1">
        <div className="flex shrink-0 items-center gap-2">{topLeft}</div>
        <div className="hidden w-[100px] shrink-0 lg:block" />
        <div className="ml-auto flex shrink-0 items-center justify-end gap-2">{topRight}</div>
      </div>
      <div className="mb-1 flex items-center gap-2 whitespace-nowrap">
        <ActionButton type="button" variant="danger" className="h-9 w-[50px] px-1 text-xs" onClick={() => void deleteSelected()}>삭제</ActionButton>
        <ActionButton type="button" variant="secondary" className="h-9 w-[50px] px-1 text-xs" onClick={() => { const targetRows = selectedRows(); if (targetRows.length) void openStatement(targetRows); else window.alert("인쇄할 행을 선택해 주세요."); }}>인쇄</ActionButton>
        <ActionButton type="button" variant="secondary" className="h-9 w-[50px] px-1 text-xs" onClick={() => { const targetRows = selectedRows(); if (targetRows.length) void openStatement(targetRows, true); else window.alert("PDF로 저장할 행을 선택해 주세요."); }}>PDF</ActionButton>
        <ActionButton type="button" variant="secondary" className="h-9 w-[58px] px-1 text-xs" onClick={() => { const targetRows = selectedRows(); if (targetRows.length) emailStatement(targetRows); else window.alert("E-mail로 보낼 행을 선택해 주세요."); }}>E-mail</ActionButton>
        <div className="ml-auto flex shrink-0 justify-end">{filterBar}</div>
      </div>
      <div className="mb-3 text-xs font-bold text-slate-500">선택 {selectedKeys.length.toLocaleString("ko-KR")}건</div>
      <div className="fn-table-shell overflow-x-auto">
        <table className="w-full min-w-[1180px] table-fixed text-sm">
          <thead className="border-b border-gray-200 bg-gray-50 text-xs font-semibold text-gray-500">
            <tr>
              <th className="w-14 py-2 text-center"><input type="checkbox" className="h-4 w-4 rounded border-slate-300" checked={selection.allSelected} onChange={(event) => selection.toggleAll(event.target.checked)} /></th>
              <th className="w-32 py-2 text-left">일자-NO.</th>
              <th className="w-44 py-2 text-left">{partnerLabel}명</th>
              <th className="w-24 py-2 text-left">창고</th>
              <th className="w-32 py-2 text-left">대표품목코드</th>
              <th className="py-2 text-left">대표품목명</th>
              <th className="w-24 py-2 text-right">품목수</th>
              <th className="w-24 py-2 text-right">수량합계</th>
              <th className="w-36 py-2 text-right">금액합계</th>
              <th className="w-40 py-2 text-center">메모</th>
            </tr>
          </thead>
          <tbody>
            {rows.map((row, index) => {
              const key = entryRowKey(row, mode, index);
              const selected = selectedKeys.includes(key);
              return (
                <tr key={key} onClick={() => onEditEntry(row)} className={`cursor-pointer border-b border-gray-100 ${selected ? "bg-orange-50" : "hover:bg-orange-50/50"}`}>
                  <td className="py-2 text-center"><SelectionNumberButton index={index} selected={selected} onMouseDown={(event) => selection.beginSelection(key, index, event)} onMouseEnter={() => selection.continueSelection(key, index)} /></td>
                  <td className="truncate py-2 font-bold text-blue-700">{entryNumbers.get(key) || compactEntryNumber(entryRowDate(row), index + 1)}</td>
                  <td className="truncate py-2">{entryRowCustomer(row, mode)}</td>
                  <td className="truncate py-2">{entryRowWarehouse(row)}</td>
                  <td className="truncate py-2">{entryRowProductCode(row) || "-"}</td>
                  <td className="truncate py-2 font-bold">{entryRowProduct(row)}</td>
                  <td className="py-2 text-right">{Number(row.line_count || 1).toLocaleString("ko-KR")}</td>
                  <td className="py-2 text-right">{entryRowQty(row).toLocaleString("ko-KR")}</td>
                  <td className="py-2 text-right font-black">{krw(entryRowAmount(row))}</td>
                  <td className="truncate py-2 text-center">{entryRowMemo(row)}</td>
                </tr>
              );
            })}
            {!rows.length && (
              <tr>
                <td colSpan={10} className="py-8 text-center text-sm font-bold text-slate-500">검색 결과가 없습니다.</td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </>
  );
}

function SalesProductMasterPanel({ message, setMessage, sync }: { message: string; setMessage: (value: string) => void; sync: (target: "products" | "inventory") => void }) {
  const [query, setQuery] = useState("");
  const [products, setProducts] = useState<FnProduct[]>([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    let alive = true;
    const params = new URLSearchParams();
    if (query.trim()) params.set("q", query.trim());
    cachedClientJson<{ products?: FnProduct[] }>(`/api/fnos/products/search?${params.toString()}`, { ttl: 5 * 60_000, storageTtl: 10 * 60_000 })
      .then((data) => {
        if (alive) setProducts(data.products || []);
      })
      .finally(() => {
        if (alive) setLoading(false);
      });
    return () => {
      alive = false;
    };
  }, [query]);

  async function linkProduct(product: FnProduct) {
    const createNew = window.confirm("새 수입관리 대표상품을 생성할까요?\n취소를 누르면 기존 수입관리 제품 ID에 연결합니다.");
    if (createNew) {
      localStorage.setItem("fnos-import-product-prefill", JSON.stringify({ product }));
      goToInternal(importHref("/products/new"));
      return;
    }
    const importProductId = window.prompt("연결할 기존 수입관리 제품 ID를 입력해 주세요.");
    if (!importProductId) return;
    const res = await fetch("/api/fnos/import-product-links", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      credentials: "include",
      body: JSON.stringify({
        import_product_id: importProductId,
        links: [{ product_id: product.id, sku: fnProductSku(product), default_ratio: 1, is_primary: true }],
      }),
    });
    const data = await res.json().catch(() => ({}));
    setMessage(res.ok && data.ok !== false ? "수입관리 대표상품에 SKU를 연결했습니다." : data.error || "연결 실패");
  }

  return (
    <Panel
      title="품목관리"
      subtitle="FN OS 품목 마스터를 관리하고 수입관리 대표상품과 연결합니다."
      action={<button type="button" className="rounded-md bg-orange-500 px-4 py-2 text-sm font-black text-white" onClick={() => sync("products")}>품목 동기화</button>}
    >
      <div className="mb-3 grid gap-2 md:grid-cols-[1fr_auto]">
        <input className="field-input" value={query} onChange={(event) => setQuery(event.target.value)} placeholder="SKU / 품목명 / 옵션 검색" />
        <Link className="inline-flex h-[38px] items-center justify-center rounded-md border border-orange-200 bg-orange-50 px-4 text-sm font-black text-orange-600" href={importHref("/products/new")}>새 수입관리 상품</Link>
      </div>
      <div className="overflow-x-auto">
        <table className="w-full min-w-[820px] text-sm">
          <thead className="border-b border-slate-200 text-xs text-slate-500">
            <tr>
              <th className="py-2 text-left">SKU</th>
              <th className="py-2 text-left">품목명</th>
              <th className="py-2 text-left">옵션</th>
              <th className="py-2 text-right">현재재고</th>
              <th className="py-2 text-right">가용재고</th>
              <th className="py-2 text-right">표준단가</th>
              <th className="py-2 text-center">수입관리</th>
            </tr>
          </thead>
          <tbody>
            {products.map((product) => (
              <tr key={product.id} className="border-b border-slate-100">
                <td className="py-2 font-black">{fnProductSku(product)}</td>
                <td className="py-2">{fnProductName(product)}</td>
                <td className="py-2">{fnProductOption(product)}</td>
                <td className="py-2 text-right">{Number(product.current_stock || 0).toLocaleString("ko-KR")}</td>
                <td className="py-2 text-right">{Number(product.available_stock || 0).toLocaleString("ko-KR")}</td>
                <td className="py-2 text-right">{krw(fnProductPrice(product))}</td>
                <td className="py-2 text-center"><button type="button" className="h-8 rounded-md border border-orange-200 px-3 text-xs font-black text-orange-600" onClick={() => void linkProduct(product)}>수입관리와 연동</button></td>
              </tr>
            ))}
          </tbody>
        </table>
        {!products.length && <p className="rounded-md bg-slate-50 px-3 py-6 text-center text-sm font-bold text-slate-400">{loading ? "" : "품목이 없습니다."}</p>}
      </div>
    </Panel>
  );
}

function SalesSummaryGroups({ summary }: { summary: SalesInventorySummary | null }) {
  const groups = [
    { title: "날짜별 매출", rows: summary?.sales_by_date || [] },
    { title: "거래처별 매출", rows: summary?.sales_by_customer || [] },
    { title: "품목별 매출", rows: summary?.sales_by_product || [] },
  ];
  return (
    <div className="mb-4 grid gap-3 lg:grid-cols-3">
      {groups.map((group) => (
        <div key={group.title} className="rounded-md border border-slate-200 bg-slate-50 p-3">
          <h3 className="text-sm font-black">{group.title}</h3>
          <div className="mt-2 space-y-2">
            {group.rows.slice(0, 5).map((row, index) => (
              <div key={`${group.title}-${String(row.label || index)}`} className="grid grid-cols-[1fr_auto] gap-2 rounded bg-white px-2 py-2 text-xs">
                <span className="truncate font-bold text-slate-700">{String(row.label || "-")}</span>
                <span className="font-black">{krw(Number(row.amount || 0))}</span>
                <span className="text-slate-500">{Number(row.count || 0).toLocaleString("ko-KR")}건</span>
                <span className="text-right text-slate-500">{Number(row.qty || 0).toLocaleString("ko-KR")}개</span>
              </div>
            ))}
            {!group.rows.length && <p className="rounded bg-white px-2 py-3 text-xs font-bold text-slate-400">데이터 없음</p>}
          </div>
        </div>
      ))}
    </div>
  );
}

